package types

import (
	"encoding/json"
	"time"
)

// ResourceQuota represents resource quota limits for a namespace
type ResourceQuota struct {
	APIVersion string            `json:"apiVersion" yaml:"apiVersion"`
	Kind       string            `json:"kind" yaml:"kind"`
	Metadata   Metadata          `json:"metadata" yaml:"metadata"`
	Spec       ResourceQuotaSpec `json:"spec" yaml:"spec"`
	Status     ResourceQuotaStatus `json:"status,omitempty" yaml:"status,omitempty"`
}

// ResourceQuotaSpec defines the desired state of ResourceQuota
type ResourceQuotaSpec struct {
	Hard ResourceLimits `json:"hard" yaml:"hard"`
}

// ResourceLimits defines the hard limits for various resources
type ResourceLimits struct {
	SessionsCount            int    `json:"sessions.count" yaml:"sessions.count"`
	SessionsCodeInterpreter  int    `json:"sessions.codeInterpreter" yaml:"sessions.codeInterpreter"`
	SessionsAgentRuntime     int    `json:"sessions.agentRuntime" yaml:"sessions.agentRuntime"`
	CPURequest               string `json:"cpu.request" yaml:"cpu.request"`
	CPULimit                 string `json:"cpu.limit" yaml:"cpu.limit"`
	MemoryRequest            string `json:"memory.request" yaml:"memory.request"`
	MemoryLimit              string `json:"memory.limit" yaml:"memory.limit"`
	StorageEphemeral         string `json:"storage.ephemeral" yaml:"storage.ephemeral"`
	StoragePersistent        string `json:"storage.persistent" yaml:"storage.persistent"`
	NetworkEgressPerSecond   string `json:"network.egressPerSecond" yaml:"network.egressPerSecond"`
	NetworkConnectionsPerSession int `json:"network.connectionsPerSession" yaml:"network.connectionsPerSession"`
	SessionMaxDuration       string `json:"session.maxDuration" yaml:"session.maxDuration"`
	SessionMaxIdleTime       string `json:"session.maxIdleTime" yaml:"session.maxIdleTime"`
}

// ResourceQuotaStatus defines the observed state of ResourceQuota
type ResourceQuotaStatus struct {
	Used      ResourceUsage `json:"used" yaml:"used"`
	Remaining ResourceUsage `json:"remaining" yaml:"remaining"`
	LastSyncTime time.Time `json:"lastSyncTime" yaml:"lastSyncTime"`
}

// ResourceUsage represents current resource usage
type ResourceUsage struct {
	SessionsCount   int    `json:"sessions.count" yaml:"sessions.count"`
	CPURequest      string `json:"cpu.request" yaml:"cpu.request"`
	MemoryRequest   string `json:"memory.request" yaml:"memory.request"`
}

// Validate validates the ResourceQuota
type ResourceQuotaValidationError struct {
	Field   string
	Message string
}

func (r *ResourceQuota) Validate() []ResourceQuotaValidationError {
	var errors []ResourceQuotaValidationError

	if r.Metadata.Name == "" {
		errors = append(errors, ResourceQuotaValidationError{
			Field:   "metadata.name",
			Message: "name is required",
		})
	}

	if r.Metadata.Namespace == "" {
		errors = append(errors, ResourceQuotaValidationError{
			Field:   "metadata.namespace",
			Message: "namespace is required",
		})
	}

	if r.Spec.Hard.SessionsCount < 0 {
		errors = append(errors, ResourceQuotaValidationError{
			Field:   "spec.hard.sessions.count",
			Message: "sessions count must be non-negative",
		})
	}

	return errors
}

// ToJSON serializes ResourceQuota to JSON
func (r *ResourceQuota) ToJSON() ([]byte, error) {
	return json.Marshal(r)
}

// FromJSON deserializes ResourceQuota from JSON
func (r *ResourceQuota) FromJSON(data []byte) error {
	return json.Unmarshal(data, r)
}

// QuotaUsage tracks resource usage for quota enforcement
type QuotaUsage struct {
	Namespace       string
	Sessions        int
	CPURequest      int64
	MemoryRequest   int64
	LastUpdated     time.Time
}

// QuotaViolation represents a quota violation
type QuotaViolation struct {
	Resource string
	Requested string
	Available string
	Message  string
}

// CanCreateSession checks if a new session can be created within quota limits
func (r *ResourceQuota) CanCreateSession(currentUsage ResourceUsage, sessionType string) *QuotaViolation {
	if currentUsage.SessionsCount >= r.Spec.Hard.SessionsCount {
		return &QuotaViolation{
			Resource:  "sessions.count",
			Requested: "1",
			Available: "0",
			Message:   "session count quota exceeded",
		}
	}

	switch sessionType {
	case "codeInterpreter":
		if currentUsage.SessionsCount >= r.Spec.Hard.SessionsCodeInterpreter {
			return &QuotaViolation{
				Resource:  "sessions.codeInterpreter",
				Requested: "1",
				Available: "0",
				Message:   "code interpreter session quota exceeded",
			}
		}
	case "agentRuntime":
		if currentUsage.SessionsCount >= r.Spec.Hard.SessionsAgentRuntime {
			return &QuotaViolation{
				Resource:  "sessions.agentRuntime",
				Requested: "1",
				Available: "0",
				Message:   "agent runtime session quota exceeded",
			}
		}
	}

	return nil
}

// QuotaMetrics represents quota metrics for monitoring
type QuotaMetrics struct {
	Namespace      string
	QuotaName      string
	ResourceType   string
	Used           float64
	Limit          float64
	Utilization    float64
	Violations     int64
	LastSyncTime   time.Time
}

package types

import (
	"encoding/json"
	"time"
)

// SessionState represents the persisted state of a session
type SessionState struct {
	SessionID    string                 `json:"sessionId"`
	CheckpointID string                 `json:"checkpointId"`
	Timestamp    time.Time              `json:"timestamp"`
	State        map[string]interface{} `json:"state"`
	Files        []FileState            `json:"files"`
	Memory       MemoryState            `json:"memory"`
}

// FileState represents the state of a file
type FileState struct {
	Path    string `json:"path"`
	Hash    string `json:"hash"`
	Size    int64  `json:"size"`
	Content []byte `json:"content,omitempty"`
}

// MemoryState represents the state of memory/variables
type MemoryState struct {
	Variables map[string]string      `json:"variables"`
	Context   map[string]interface{} `json:"context"`
}

// Checkpoint represents a session checkpoint
type Checkpoint struct {
	APIVersion string            `json:"apiVersion" yaml:"apiVersion"`
	Kind       string            `json:"kind" yaml:"kind"`
	Metadata   Metadata          `json:"metadata" yaml:"metadata"`
	Spec       CheckpointSpec    `json:"spec" yaml:"spec"`
	Status     CheckpointStatus  `json:"status,omitempty" yaml:"status,omitempty"`
}

// CheckpointSpec defines the desired state of a checkpoint
type CheckpointSpec struct {
	SessionID     string            `json:"sessionId" yaml:"sessionId"`
	StateToPersist []string         `json:"stateToPersist" yaml:"stateToPersist"`
	Storage       CheckpointStorage `json:"storage" yaml:"storage"`
}

// CheckpointStorage defines storage configuration for checkpoints
type CheckpointStorage struct {
	Type     string            `json:"type" yaml:"type"` // s3, gcs, azure, pvc
	S3       *S3Storage        `json:"s3,omitempty" yaml:"s3,omitempty"`
	GCS      *GCSStorage       `json:"gcs,omitempty" yaml:"gcs,omitempty"`
	Azure    *AzureStorage     `json:"azure,omitempty" yaml:"azure,omitempty"`
	PVC      *PVCStorage       `json:"pvc,omitempty" yaml:"pvc,omitempty"`
}

// S3Storage defines S3 storage configuration
type S3Storage struct {
	Bucket   string `json:"bucket" yaml:"bucket"`
	Region   string `json:"region" yaml:"region"`
	Prefix   string `json:"prefix" yaml:"prefix"`
	Endpoint string `json:"endpoint,omitempty" yaml:"endpoint,omitempty"`
}

// GCSStorage defines GCS storage configuration
type GCSStorage struct {
	Bucket string `json:"bucket" yaml:"bucket"`
	Prefix string `json:"prefix" yaml:"prefix"`
}

// AzureStorage defines Azure storage configuration
type AzureStorage struct {
	Container string `json:"container" yaml:"container"`
	Prefix    string `json:"prefix" yaml:"prefix"`
}

// PVCStorage defines PVC storage configuration
type PVCStorage struct {
	Name      string `json:"name" yaml:"name"`
	Namespace string `json:"namespace" yaml:"namespace"`
	Path      string `json:"path" yaml:"path"`
}

// CheckpointStatus defines the observed state of a checkpoint
type CheckpointStatus struct {
	Phase      Phase       `json:"phase" yaml:"phase"`
	Size       int64       `json:"size" yaml:"size"`
	Location   string      `json:"location" yaml:"location"`
	Conditions []Condition `json:"conditions,omitempty" yaml:"conditions,omitempty"`
	CompletedAt time.Time  `json:"completedAt,omitempty" yaml:"completedAt,omitempty"`
}

// ToJSON serializes SessionState to JSON
func (s *SessionState) ToJSON() ([]byte, error) {
	return json.Marshal(s)
}

// FromJSON deserializes SessionState from JSON
func (s *SessionState) FromJSON(data []byte) error {
	return json.Unmarshal(data, s)
}

// CalculateSize calculates the total size of the checkpoint
func (s *SessionState) CalculateSize() int64 {
	size := int64(0)
	for _, f := range s.Files {
		size += f.Size
	}
	size += int64(len(s.Memory.Variables))
	return size
}

// RecoveryScenario represents a session recovery scenario
type RecoveryScenario string

const (
	RecoveryPodFailure    RecoveryScenario = "PodFailure"
	RecoveryNodeMigration RecoveryScenario = "NodeMigration"
	RecoveryManualRestore RecoveryScenario = "ManualRestore"
	RecoveryScheduled     RecoveryScenario = "ScheduledBackup"
)

// RecoveryRequest represents a session recovery request
type RecoveryRequest struct {
	SessionID      string           `json:"sessionId"`
	CheckpointID   string           `json:"checkpointId,omitempty"`
	Scenario       RecoveryScenario `json:"scenario"`
	TargetNode     string           `json:"targetNode,omitempty"`
	RequestedAt    time.Time        `json:"requestedAt"`
}

// RecoveryResult represents the result of a recovery operation
type RecoveryResult struct {
	SessionID      string    `json:"sessionId"`
	CheckpointID   string    `json:"checkpointId"`
	Success        bool      `json:"success"`
	NewPodName     string    `json:"newPodName,omitempty"`
	ErrorMessage   string    `json:"errorMessage,omitempty"`
	CompletedAt    time.Time `json:"completedAt"`
	DurationMs     int64     `json:"durationMs"`
}

// CheckpointRetentionPolicy defines retention policy for checkpoints
type CheckpointRetentionPolicy struct {
	MaxCheckpoints int           `json:"maxCheckpoints"`
	MaxAge         time.Duration `json:"maxAge"`
}

// ShouldDelete determines if a checkpoint should be deleted based on retention policy
func (c *Checkpoint) ShouldDelete(policy CheckpointRetentionPolicy, totalCheckpoints int) bool {
	if policy.MaxCheckpoints > 0 && totalCheckpoints > policy.MaxCheckpoints {
		return true
	}

	if policy.MaxAge > 0 {
		age := time.Since(c.Status.CompletedAt)
		if age > policy.MaxAge {
			return true
		}
	}

	return false
}

package types

import (
	"time"
)

// Metadata represents common metadata for all CRDs
type Metadata struct {
	Name              string            `json:"name" yaml:"name"`
	Namespace         string            `json:"namespace,omitempty" yaml:"namespace,omitempty"`
	Labels            map[string]string `json:"labels,omitempty" yaml:"labels,omitempty"`
	Annotations       map[string]string `json:"annotations,omitempty" yaml:"annotations,omitempty"`
	CreationTimestamp time.Time         `json:"creationTimestamp,omitempty" yaml:"creationTimestamp,omitempty"`
	UID               string            `json:"uid,omitempty" yaml:"uid,omitempty"`
	ResourceVersion   string            `json:"resourceVersion,omitempty" yaml:"resourceVersion,omitempty"`
}

// GetLabel gets a label value by key
func (m *Metadata) GetLabel(key string) string {
	if m.Labels == nil {
		return ""
	}
	return m.Labels[key]
}

// SetLabel sets a label value
func (m *Metadata) SetLabel(key, value string) {
	if m.Labels == nil {
		m.Labels = make(map[string]string)
	}
	m.Labels[key] = value
}

// GetAnnotation gets an annotation value by key
func (m *Metadata) GetAnnotation(key string) string {
	if m.Annotations == nil {
		return ""
	}
	return m.Annotations[key]
}

// SetAnnotation sets an annotation value
func (m *Metadata) SetAnnotation(key, value string) {
	if m.Annotations == nil {
		m.Annotations = make(map[string]string)
	}
	m.Annotations[key] = value
}

// ListOptions represents options for listing resources
type ListOptions struct {
	Namespace     string
	LabelSelector string
	FieldSelector string
	Limit         int
	Continue      string
}

// ListResult represents a list of resources
type ListResult struct {
	Items      []interface{} `json:"items"`
	TotalCount int           `json:"totalCount"`
	Continue   string        `json:"continue,omitempty"`
}

// ConditionStatus represents the status of a condition
type ConditionStatus string

const (
	ConditionTrue    ConditionStatus = "True"
	ConditionFalse   ConditionStatus = "False"
	ConditionUnknown ConditionStatus = "Unknown"
)

// Condition represents a condition of a resource
type Condition struct {
	Type               string          `json:"type"`
	Status             ConditionStatus `json:"status"`
	LastTransitionTime time.Time       `json:"lastTransitionTime,omitempty"`
	Reason             string          `json:"reason,omitempty"`
	Message            string          `json:"message,omitempty"`
}

// Phase represents the phase of a resource
type Phase string

const (
	PhasePending   Phase = "Pending"
	PhaseRunning   Phase = "Running"
	PhaseSucceeded Phase = "Succeeded"
	PhaseFailed    Phase = "Failed"
	PhaseUnknown   Phase = "Unknown"
)

package types

import (
	"encoding/json"
	"time"
)

// SessionSecret represents a secret for injection into sandbox sessions
type SessionSecret struct {
	APIVersion string              `json:"apiVersion" yaml:"apiVersion"`
	Kind       string              `json:"kind" yaml:"kind"`
	Metadata   Metadata            `json:"metadata" yaml:"metadata"`
	Spec       SessionSecretSpec   `json:"spec" yaml:"spec"`
	Status     SessionSecretStatus `json:"status,omitempty" yaml:"status,omitempty"`
}

// SessionSecretSpec defines the desired state of SessionSecret
type SessionSecretSpec struct {
	Type            SecretType            `json:"type" yaml:"type"`
	Data            map[string]string     `json:"data" yaml:"data"`
	Immutable       bool                  `json:"immutable" yaml:"immutable"`
	AllowedRuntimes []SecretRuntimeRef    `json:"allowedRuntimes,omitempty" yaml:"allowedRuntimes,omitempty"`
	AllowedUsers    []string              `json:"allowedUsers,omitempty" yaml:"allowedUsers,omitempty"`
}

// SecretType represents the type of secret
type SecretType string

const (
	SecretTypeOpaque     SecretType = "Opaque"
	SecretTypeTLS        SecretType = "TLS"
	SecretTypeBasicAuth  SecretType = "BasicAuth"
)

// SecretRuntimeRef references a runtime that can access this secret
type SecretRuntimeRef struct {
	Name      string `json:"name" yaml:"name"`
	Namespace string `json:"namespace" yaml:"namespace"`
}

// SessionSecretStatus defines the observed state of SessionSecret
type SessionSecretStatus struct {
	Phase      Phase     `json:"phase" yaml:"phase"`
	Conditions []Condition `json:"conditions,omitempty" yaml:"conditions,omitempty"`
	LastSyncTime time.Time `json:"lastSyncTime,omitempty" yaml:"lastSyncTime,omitempty"`
}

// SecretMapping defines how a secret should be mapped to a runtime
type SecretMapping struct {
	Name         string            `json:"name" yaml:"name"`
	Namespace    string            `json:"namespace" yaml:"namespace"`
	EnvMappings  []EnvMapping      `json:"envMappings,omitempty" yaml:"envMappings,omitempty"`
	FileMappings []FileMapping     `json:"fileMappings,omitempty" yaml:"fileMappings,omitempty"`
}

// EnvMapping maps a secret key to an environment variable
type EnvMapping struct {
	SecretKey string `json:"secretKey" yaml:"secretKey"`
	EnvName   string `json:"envName" yaml:"envName"`
}

// FileMapping maps a secret key to a file
type FileMapping struct {
	SecretKey string `json:"secretKey" yaml:"secretKey"`
	MountPath string `json:"mountPath" yaml:"mountPath"`
	Mode      int32  `json:"mode" yaml:"mode"`
}

// Validate validates the SessionSecret
func (s *SessionSecret) Validate() []string {
	var errors []string

	if s.Metadata.Name == "" {
		errors = append(errors, "metadata.name is required")
	}

	if s.Metadata.Namespace == "" {
		errors = append(errors, "metadata.namespace is required")
	}

	if s.Spec.Type == "" {
		errors = append(errors, "spec.type is required")
	}

	if len(s.Spec.Data) == 0 {
		errors = append(errors, "spec.data cannot be empty")
	}

	return errors
}

// ToJSON serializes SessionSecret to JSON
func (s *SessionSecret) ToJSON() ([]byte, error) {
	return json.Marshal(s)
}

// FromJSON deserializes SessionSecret from JSON
func (s *SessionSecret) FromJSON(data []byte) error {
	return json.Unmarshal(data, s)
}

// CanAccess checks if a runtime or user can access this secret
func (s *SessionSecret) CanAccess(runtimeName, runtimeNamespace, user string) bool {
	if len(s.Spec.AllowedRuntimes) == 0 && len(s.Spec.AllowedUsers) == 0 {
		return true
	}

	for _, r := range s.Spec.AllowedRuntimes {
		if r.Name == runtimeName && r.Namespace == runtimeNamespace {
			return true
		}
	}

	for _, u := range s.Spec.AllowedUsers {
		if u == user {
			return true
		}
	}

	return false
}

// DecryptData decrypts the secret data using the provided decryption function
func (s *SessionSecret) DecryptData(decryptFunc func(string) (string, error)) (map[string]string, error) {
	decrypted := make(map[string]string)
	for key, value := range s.Spec.Data {
		decryptedValue, err := decryptFunc(value)
		if err != nil {
			return nil, err
		}
		decrypted[key] = decryptedValue
	}
	return decrypted, nil
}

// SecretRotation represents a secret rotation event
type SecretRotation struct {
	SecretName    string    `json:"secretName"`
	Namespace     string    `json:"namespace"`
	OldVersion    string    `json:"oldVersion"`
	NewVersion    string    `json:"newVersion"`
	RotatedAt     time.Time `json:"rotatedAt"`
	RotatedBy     string    `json:"rotatedBy"`
}

// SecretAccessLog represents an audit log entry for secret access
type SecretAccessLog struct {
	Timestamp   time.Time `json:"timestamp"`
	SecretName  string    `json:"secretName"`
	Namespace   string    `json:"namespace"`
	Action      string    `json:"action"`
	User        string    `json:"user"`
	Runtime     string    `json:"runtime"`
	Success     bool      `json:"success"`
	ErrorMessage string   `json:"errorMessage,omitempty"`
}

package types

import (
	"encoding/json"
)

// SessionInsights represents session-level insights and metrics
type SessionInsights struct {
	SessionID string                 `json:"sessionId"`
	Metrics   SessionMetrics         `json:"metrics"`
	Events    []SessionEvent         `json:"events"`
}

// SessionMetrics contains various metrics for a session
type SessionMetrics struct {
	CPUUsage     ResourceMetric   `json:"cpu_usage"`
	MemoryUsage  ResourceMetric   `json:"memory_usage"`
	NetworkIO    NetworkMetrics   `json:"network_io"`
	Duration     int64            `json:"duration_ms"`
}

// ResourceMetric represents a resource metric with current, peak, and average values
type ResourceMetric struct {
	Current float64 `json:"current"`
	Peak    float64 `json:"peak"`
	Average float64 `json:"average"`
}

// NetworkMetrics represents network I/O metrics
type NetworkMetrics struct {
	BytesIn  int64 `json:"bytes_in"`
	BytesOut int64 `json:"bytes_out"`
}

// SessionEvent represents an event in the session lifecycle
type SessionEvent struct {
	Timestamp string                 `json:"timestamp"`
	Type      string                 `json:"type"`
	Details   map[string]interface{} `json:"details"`
}

// StructuredLog represents a structured log entry
type StructuredLog struct {
	Timestamp   string                 `json:"timestamp"`
	Level       string                 `json:"level"`
	Component   string                 `json:"component"`
	TraceID     string                 `json:"trace_id"`
	SpanID      string                 `json:"span_id"`
	Tenant      string                 `json:"tenant"`
	Namespace   string                 `json:"namespace"`
	SessionID   string                 `json:"session_id"`
	Event       string                 `json:"event"`
	DurationMs  int64                  `json:"duration_ms"`
	Metadata    map[string]interface{} `json:"metadata"`
	Message     string                 `json:"message"`
}

// ToJSON serializes StructuredLog to JSON
func (l *StructuredLog) ToJSON() ([]byte, error) {
	return json.Marshal(l)
}

// FromJSON deserializes StructuredLog from JSON
func (l *StructuredLog) FromJSON(data []byte) error {
	return json.Unmarshal(data, l)
}

// MetricType represents different types of metrics
type MetricType string

const (
	MetricTypeCounter   MetricType = "counter"
	MetricTypeGauge     MetricType = "gauge"
	MetricTypeHistogram MetricType = "histogram"
	MetricTypeSummary   MetricType = "summary"
)

// Metric represents a generic metric
type Metric struct {
	Name   string            `json:"name"`
	Type   MetricType        `json:"type"`
	Value  float64           `json:"value"`
	Labels map[string]string `json:"labels"`
	Time   int64             `json:"time"`
}

// SessionMetricLabels represents common labels for session metrics
type SessionMetricLabels struct {
	Namespace   string
	RuntimeType string
	Tenant      string
	SessionID   string
}

// ToMap converts SessionMetricLabels to a map
func (l *SessionMetricLabels) ToMap() map[string]string {
	return map[string]string{
		"namespace":    l.Namespace,
		"runtime_type": l.RuntimeType,
		"tenant":       l.Tenant,
		"session_id":   l.SessionID,
	}
}

// ResourceUsageMetric represents resource usage metrics
type ResourceUsageMetric struct {
	Namespace    string  `json:"namespace"`
	ResourceType string  `json:"resource_type"`
	Unit         string  `json:"unit"`
	Value        float64 `json:"value"`
}

// AlertRule represents an alerting rule
type AlertRule struct {
	Name        string            `json:"name"`
	Expr        string            `json:"expr"`
	Duration    string            `json:"duration"`
	Labels      map[string]string `json:"labels"`
	Annotations map[string]string `json:"annotations"`
}

// Alert represents a triggered alert
type Alert struct {
	Name        string            `json:"name"`
	Status      string            `json:"status"`
	Labels      map[string]string `json:"labels"`
	Annotations map[string]string `json:"annotations"`
	StartsAt    int64             `json:"startsAt"`
	EndsAt      int64             `json:"endsAt,omitempty"`
}

// TracingContext represents distributed tracing context
type TracingContext struct {
	TraceID string `json:"trace_id"`
	SpanID  string `json:"span_id"`
	ParentSpanID string `json:"parent_span_id,omitempty"`
	Sampled bool   `json:"sampled"`
}

// NewTracingContext creates a new tracing context
func NewTracingContext(traceID, spanID string) *TracingContext {
	return &TracingContext{
		TraceID: traceID,
		SpanID:  spanID,
		Sampled: true,
	}
}

// WithParent sets the parent span ID
func (t *TracingContext) WithParent(parentSpanID string) *TracingContext {
	t.ParentSpanID = parentSpanID
	return t
}

// LogLevel represents log levels
type LogLevel string

const (
	LogLevelDebug LogLevel = "DEBUG"
	LogLevelInfo  LogLevel = "INFO"
	LogLevelWarn  LogLevel = "WARN"
	LogLevelError LogLevel = "ERROR"
)

// IsValid checks if log level is valid
func (l LogLevel) IsValid() bool {
	switch l {
	case LogLevelDebug, LogLevelInfo, LogLevelWarn, LogLevelError:
		return true
	}
	return false
}

package types

import (
	"encoding/json"
)

// Tenant represents a tenant in the multi-tenant system
type Tenant struct {
	APIVersion string          `json:"apiVersion" yaml:"apiVersion"`
	Kind       string          `json:"kind" yaml:"kind"`
	Metadata   Metadata        `json:"metadata" yaml:"metadata"`
	Spec       TenantSpec      `json:"spec" yaml:"spec"`
	Status     TenantStatus    `json:"status,omitempty" yaml:"status,omitempty"`
}

// TenantSpec defines the desired state of Tenant
type TenantSpec struct {
	DisplayName string              `json:"displayName" yaml:"displayName"`
	Admins      []string            `json:"admins" yaml:"admins"`
	Namespaces  []string            `json:"namespaces" yaml:"namespaces"`
	Isolation   TenantIsolation     `json:"isolation" yaml:"isolation"`
}

// TenantIsolation defines isolation settings for a tenant
type TenantIsolation struct {
	Network NetworkIsolation    `json:"network" yaml:"network"`
	Storage StorageIsolation    `json:"storage" yaml:"storage"`
	Compute ComputeIsolation    `json:"compute" yaml:"compute"`
}

// NetworkIsolation defines network isolation settings
type NetworkIsolation struct {
	Enabled          bool                   `json:"enabled" yaml:"enabled"`
	AllowEgress      bool                   `json:"allowEgress" yaml:"allowEgress"`
	AllowedEndpoints []AllowedEndpoint      `json:"allowedEndpoints,omitempty" yaml:"allowedEndpoints,omitempty"`
}

// AllowedEndpoint defines an allowed network endpoint
type AllowedEndpoint struct {
