// Validate validates the Tenant
func (t *Tenant) Validate() []string {
	var errors []string

	if t.Metadata.Name == "" {
		errors = append(errors, "metadata.name is required")
	}

	if t.Spec.DisplayName == "" {
		errors = append(errors, "spec.displayName is required")
	}

	if len(t.Spec.Admins) == 0 {
		errors = append(errors, "spec.admins cannot be empty")
	}

	return errors
}

// ToJSON serializes Tenant to JSON
func (t *Tenant) ToJSON() ([]byte, error) {
	return json.Marshal(t)
}

// FromJSON deserializes Tenant from JSON
func (t *Tenant) FromJSON(data []byte) error {
	return json.Unmarshal(data, t)
}

// CanAccess checks if source tenant can access target tenant's resource
func (p *TenantAccessPolicy) CanAccess(sourceTenant, targetTenant, operation, namespace, name string) bool {
	if p.Spec.SourceTenant != sourceTenant || p.Spec.TargetTenant != targetTenant {
		return false
	}

	for _, op := range p.Spec.AllowedOperations {
		if op.Type == operation {
			for _, res := range op.Resources {
				if res.Namespace == namespace && res.Name == name {
					return true
				}
			}
		}
	}

	return false
}

// IsResourceIsolated checks if resource is isolated within tenant boundaries
func (t *Tenant) IsResourceIsolated(namespace string) bool {
	for _, ns := range t.Spec.Namespaces {
		if ns == namespace {
			return true
		}
	}
	return false
}

// IsolationLevel represents the level of isolation
type IsolationLevel string

const (
	IsolationLevelNamespace IsolationLevel = "Namespace"
	IsolationLevelNetwork   IsolationLevel = "Network"
	IsolationLevelStorage   IsolationLevel = "Storage"
	IsolationLevelCompute   IsolationLevel = "Compute"
	IsolationLevelIdentity  IsolationLevel = "Identity"
)

// GetIsolationLevel returns whether a specific isolation level is enabled
func (t *Tenant) GetIsolationLevel(level IsolationLevel) bool {
	switch level {
	case IsolationLevelNetwork:
		return t.Spec.Isolation.Network.Enabled
	case IsolationLevelStorage:
		return t.Spec.Isolation.Storage.Enabled
	case IsolationLevelCompute:
		return len(t.Spec.Isolation.Compute.NodeSelector) > 0
	default:
		return true
	}
}

