	return json.Marshal(s)
}

// FromJSON deserializes SandboxAutoscaler from JSON
func (s *SandboxAutoscaler) FromJSON(data []byte) error {
	return json.Unmarshal(data, s)
}

// Validate validates the SandboxAutoscaler
func (s *SandboxAutoscaler) Validate() []string {
	var errors []string

	if s.Metadata.Name == "" {
		errors = append(errors, "metadata.name is required")
	}

	if s.Spec.TargetRef.Name == "" {
		errors = append(errors, "spec.targetRef.name is required")
	}

	if s.Spec.MinReplicas < 0 {
		errors = append(errors, "spec.minReplicas must be non-negative")
	}

	if s.Spec.MaxReplicas <= 0 {
		errors = append(errors, "spec.maxReplicas must be positive")
	}

	if s.Spec.MinReplicas > s.Spec.MaxReplicas {
		errors = append(errors, "spec.minReplicas cannot be greater than spec.maxReplicas")
	}

	return errors
}

// ScalingType represents the type of scaling
type ScalingType string

const (
	ScalingTypeHorizontal ScalingType = "Horizontal"
	ScalingTypeVertical   ScalingType = "Vertical"
	ScalingTypeWarmPool   ScalingType = "WarmPool"
)

// ShouldScale determines if scaling is needed based on current metrics
func (s *SandboxAutoscaler) ShouldScale(currentReplicas int32, metrics map[string]float64) (int32, bool) {
	if currentReplicas < s.Spec.MinReplicas {
		return s.Spec.MinReplicas, true
	}

	if currentReplicas > s.Spec.MaxReplicas {
		return s.Spec.MaxReplicas, true
	}

	for _, metric := range s.Spec.Metrics {
		if metric.Type == MetricSourceTypeResource && metric.Resource != nil {
			metricName := metric.Resource.Name
			if value, ok := metrics[metricName]; ok {
				if metric.Resource.Target.Type == MetricTargetTypeUtilization {
					targetUtilization := float64(*metric.Resource.Target.AverageUtilization)
					if value > targetUtilization && currentReplicas < s.Spec.MaxReplicas {
						return currentReplicas + 1, true
					}
					if value < targetUtilization/2 && currentReplicas > s.Spec.MinReplicas {
						return currentReplicas - 1, true
					}
				}
			}
		}
	}

	return currentReplicas, false
}

