// ToJSON serializes Policy to JSON
func (p *Policy) ToJSON() ([]byte, error) {
	return json.Marshal(p)
}

// FromJSON deserializes Policy from JSON
func (p *Policy) FromJSON(data []byte) error {
	return json.Unmarshal(data, p)
}

// Validate validates the Policy
func (p *Policy) Validate() []string {
	var errors []string

	if p.Metadata.Name == "" {
		errors = append(errors, "metadata.name is required")
	}

	if p.Spec.Enforcement == "" {
		errors = append(errors, "spec.enforcement is required")
	}

	if len(p.Spec.Rules) == 0 {
		errors = append(errors, "spec.rules cannot be empty")
	}

	for i, rule := range p.Spec.Rules {
		if rule.Name == "" {
			errors = append(errors, "rule["+string(rune(i))+"].name is required")
		}
		if rule.Target == "" {
			errors = append(errors, "rule["+string(rune(i))+"].target is required")
		}
		if rule.Condition == "" {
			errors = append(errors, "rule["+string(rune(i))+"].condition is required")
		}
	}

	return errors
}

// AddViolation adds a violation to the policy status
func (p *Policy) AddViolation(violation PolicyViolation) {
	p.Status.Violations = append(p.Status.Violations, violation)
}

// ClearViolations clears all violations
func (p *Policy) ClearViolations() {
	p.Status.Violations = nil
}

// PolicyType represents the type of policy
type PolicyType string

const (
	PolicyTypeSecurity    PolicyType = "Security"
	PolicyTypeResource    PolicyType = "Resource"
	PolicyTypeCompliance  PolicyType = "Compliance"
	PolicyTypeOperational PolicyType = "Operational"
)

// PolicyLibrary represents a library of default policies
type PolicyLibrary struct {
	Policies []Policy `json:"policies"`
}

// GetDefaultPolicies returns a set of default policies
func GetDefaultPolicies() []Policy {
	return []Policy{
		{
			APIVersion: "runtime.agentcube.volcano.sh/v1alpha1",
			Kind:       "Policy",
			Metadata:   Metadata{Name: "restrict-egress", Namespace: "default"},
			Spec: PolicySpec{
				Enforcement: EnforcementModeEnforce,
				Rules: []PolicyRule{
					{
						Name:      "no-egress-in-production",
						Target:    "Session",
						Condition: "session.spec.network.egress.enabled == true",
						Action:    PolicyActionDeny,
						Message:   "Egress must be disabled in production",
					},
				},
			},
		},
	}
}

