package controllers

import (
	"context"
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"io"
	"sync"
	"time"

	"github.com/volcengine/agentcube/pkg/types"
)

// SecretController manages session secrets
type SecretController struct {
	secrets    map[string]*types.SessionSecret
	accessLogs []types.SecretAccessLog
	mu         sync.RWMutex
	encryptionKey []byte
}

// NewSecretController creates a new secret controller
func NewSecretController(encryptionKey []byte) *SecretController {
	return &SecretController{
		secrets:       make(map[string]*types.SessionSecret),
		accessLogs:    make([]types.SecretAccessLog, 0),
		encryptionKey: encryptionKey,
	}
}

// CreateSecret creates a new secret
func (c *SecretController) CreateSecret(ctx context.Context, secret *types.SessionSecret) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", secret.Metadata.Namespace, secret.Metadata.Name)

	if _, exists := c.secrets[key]; exists {
		return fmt.Errorf("secret %s already exists", key)
	}

	errors := secret.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	// Encrypt secret data
	encryptedData := make(map[string]string)
	for k, v := range secret.Spec.Data {
		encrypted, err := c.encrypt(v)
		if err != nil {
			return fmt.Errorf("failed to encrypt secret data: %v", err)
		}
		encryptedData[k] = encrypted
	}
	secret.Spec.Data = encryptedData

	secret.Status.Phase = types.PhasePending
	c.secrets[key] = secret

	// Log access
	c.logAccess(secret.Metadata.Name, secret.Metadata.Namespace, "create", "", "", true, "")

	return nil
}

// GetSecret gets a secret
func (c *SecretController) GetSecret(namespace, name string) (*types.SessionSecret, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	secret, exists := c.secrets[key]
	if !exists {
		return nil, fmt.Errorf("secret %s not found", key)
	}

	return secret, nil
}

// GetSecretDecrypted gets a secret with decrypted data
func (c *SecretController) GetSecretDecrypted(namespace, name, runtimeName, runtimeNamespace, user string) (*types.SessionSecret, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	secret, exists := c.secrets[key]
	if !exists {
		c.logAccess(name, namespace, "get", user, runtimeName, false, "secret not found")
		return nil, fmt.Errorf("secret %s not found", key)
	}

	// Check access
	if !secret.CanAccess(runtimeName, runtimeNamespace, user) {
		c.logAccess(name, namespace, "get", user, runtimeName, false, "access denied")
		return nil, fmt.Errorf("access denied to secret %s", key)
	}

	// Decrypt data
	decryptedData := make(map[string]string)
	for k, v := range secret.Spec.Data {
		decrypted, err := c.decrypt(v)
		if err != nil {
			c.logAccess(name, namespace, "get", user, runtimeName, false, err.Error())
			return nil, fmt.Errorf("failed to decrypt secret data: %v", err)
		}
		decryptedData[k] = decrypted
	}

	// Create a copy with decrypted data
	result := &types.SessionSecret{
		APIVersion: secret.APIVersion,
		Kind:       secret.Kind,
		Metadata:   secret.Metadata,
		Spec:       secret.Spec,
		Status:     secret.Status,
	}
	result.Spec.Data = decryptedData

	c.logAccess(name, namespace, "get", user, runtimeName, true, "")

	return result, nil
}

// UpdateSecret updates a secret
func (c *SecretController) UpdateSecret(ctx context.Context, secret *types.SessionSecret) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", secret.Metadata.Namespace, secret.Metadata.Name)

	existing, exists := c.secrets[key]
	if !exists {
		return fmt.Errorf("secret %s not found", key)
	}

	if existing.Spec.Immutable {
		return fmt.Errorf("secret %s is immutable", key)
	}

	errors := secret.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	// Re-encrypt if needed
	encryptedData := make(map[string]string)
	for k, v := range secret.Spec.Data {
		encrypted, err := c.encrypt(v)
		if err != nil {
			return fmt.Errorf("failed to encrypt secret data: %v", err)
		}
		encryptedData[k] = encrypted
	}
	secret.Spec.Data = encryptedData

	c.secrets[key] = secret

	c.logAccess(secret.Metadata.Name, secret.Metadata.Namespace, "update", "", "", true, "")

	return nil
}

// DeleteSecret deletes a secret
func (c *SecretController) DeleteSecret(namespace, name string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)

	if _, exists := c.secrets[key]; !exists {
		return fmt.Errorf("secret %s not found", key)
	}

	delete(c.secrets, key)

	c.logAccess(name, namespace, "delete", "", "", true, "")

	return nil
}

// ListSecrets lists all secrets in a namespace
func (c *SecretController) ListSecrets(namespace string) []*types.SessionSecret {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.SessionSecret
	for _, secret := range c.secrets {
		if secret.Metadata.Namespace == namespace {
			result = append(result, secret)
		}
	}

	return result
}

// RotateSecret rotates a secret
func (c *SecretController) RotateSecret(ctx context.Context, namespace, name, newValue, rotatedBy string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	secret, exists := c.secrets[key]
	if !exists {
		return fmt.Errorf("secret %s not found", key)
	}

	if secret.Spec.Immutable {
		return fmt.Errorf("secret %s is immutable", key)
	}

	// Encrypt new value
	encrypted, err := c.encrypt(newValue)
	if err != nil {
		return fmt.Errorf("failed to encrypt new secret value: %v", err)
	}

	// Update all keys with new value (simplified rotation)
	for k := range secret.Spec.Data {
		secret.Spec.Data[k] = encrypted
	}

	secret.Status.LastSyncTime = time.Now()

	c.logAccess(name, namespace, "rotate", rotatedBy, "", true, "")

	return nil
}

// GetAccessLogs returns access logs
func (c *SecretController) GetAccessLogs(namespace, name string, limit int) []types.SecretAccessLog {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []types.SecretAccessLog
	for i := len(c.accessLogs) - 1; i >= 0 && len(result) < limit; i-- {
		log := c.accessLogs[i]
		if log.Namespace == namespace && log.SecretName == name {
			result = append(result, log)
		}
	}

	return result
}

// logAccess logs a secret access
func (c *SecretController) logAccess(secretName, namespace, action, user, runtime string, success bool, errorMsg string) {
	log := types.SecretAccessLog{
		Timestamp:    time.Now(),
		SecretName:   secretName,
		Namespace:    namespace,
		Action:       action,
		User:         user,
		Runtime:      runtime,
		Success:      success,
		ErrorMessage: errorMsg,
	}

	c.accessLogs = append(c.accessLogs, log)

	// Keep only last 10000 logs
	if len(c.accessLogs) > 10000 {
		c.accessLogs = c.accessLogs[len(c.accessLogs)-10000:]
	}
}

// encrypt encrypts data using AES-GCM
func (c *SecretController) encrypt(plaintext string) (string, error) {
	block, err := aes.NewCipher(c.encryptionKey)
	if err != nil {
		return "", err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return "", err
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err = io.ReadFull(rand.Reader, nonce); err != nil {
		return "", err
	}

	ciphertext := gcm.Seal(nonce, nonce, []byte(plaintext), nil)
	return base64.StdEncoding.EncodeToString(ciphertext), nil
}

// decrypt decrypts data using AES-GCM
func (c *SecretController) decrypt(ciphertext string) (string, error) {
	data, err := base64.StdEncoding.DecodeString(ciphertext)
	if err != nil {
		return "", err
	}

	block, err := aes.NewCipher(c.encryptionKey)
	if err != nil {
		return "", err
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return "", err
	}

	nonceSize := gcm.NonceSize()
	if len(data) < nonceSize {
		return "", fmt.Errorf("ciphertext too short")
	}

	nonce, ciphertextBytes := data[:nonceSize], data[nonceSize:]
	plaintext, err := gcm.Open(nil, nonce, ciphertextBytes, nil)
	if err != nil {
		return "", err
	}

	return string(plaintext), nil
}

// InjectSecret injects a secret into a runtime configuration
func (c *SecretController) InjectSecret(namespace, name, runtimeName, runtimeNamespace string, mappings types.SecretMapping) error {
	secret, err := c.GetSecretDecrypted(namespace, name, runtimeName, runtimeNamespace, "")
	if err != nil {
		return err
	}

	// Validate mappings against secret keys
	for _, envMap := range mappings.EnvMappings {
		if _, exists := secret.Spec.Data[envMap.SecretKey]; !exists {
			return fmt.Errorf("secret key %s not found", envMap.SecretKey)
		}
	}

	for _, fileMap := range mappings.FileMappings {
		if _, exists := secret.Spec.Data[fileMap.SecretKey]; !exists {
			return fmt.Errorf("secret key %s not found", fileMap.SecretKey)
		}
	}

	return nil
}

package controllers

import (
	"bytes"
	"compress/gzip"
	"context"
	"crypto/sha256"
	"encoding/json"
	"fmt"
	"io"
	"sync"
	"time"

	"github.com/volcengine/agentcube/pkg/types"
)

// CheckpointController manages session checkpoints
type CheckpointController struct {
	checkpoints    map[string]*types.Checkpoint
	sessionStates  map[string]*types.SessionState
	storageBackends map[string]CheckpointStorageBackend
	mu             sync.RWMutex
}

// CheckpointStorageBackend interface for storage backends
type CheckpointStorageBackend interface {
	Save(key string, data []byte) error
	Load(key string) ([]byte, error)
	Delete(key string) error
	List(prefix string) ([]string, error)
}

// NewCheckpointController creates a new checkpoint controller
func NewCheckpointController() *CheckpointController {
	return &CheckpointController{
		checkpoints:     make(map[string]*types.Checkpoint),
		sessionStates:   make(map[string]*types.SessionState),
		storageBackends: make(map[string]CheckpointStorageBackend),
	}
}

// RegisterStorageBackend registers a storage backend
func (c *CheckpointController) RegisterStorageBackend(name string, backend CheckpointStorageBackend) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.storageBackends[name] = backend
}

// CreateCheckpoint creates a new checkpoint
func (c *CheckpointController) CreateCheckpoint(ctx context.Context, checkpoint *types.Checkpoint) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", checkpoint.Metadata.Namespace, checkpoint.Metadata.Name)

	if _, exists := c.checkpoints[key]; exists {
		return fmt.Errorf("checkpoint %s already exists", key)
	}

	checkpoint.Status.Phase = types.PhasePending
	c.checkpoints[key] = checkpoint

	return nil
}

// SaveSessionState saves session state to storage
func (c *CheckpointController) SaveSessionState(ctx context.Context, sessionID string, state *types.SessionState, storage types.CheckpointStorage) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	// Serialize state
	data, err := state.ToJSON()
	if err != nil {
		return fmt.Errorf("failed to serialize state: %v", err)
	}

	// Compress data
	var compressedData bytes.Buffer
	gzipWriter := gzip.NewWriter(&compressedData)
	if _, err := gzipWriter.Write(data); err != nil {
		return fmt.Errorf("failed to compress state: %v", err)
	}
	gzipWriter.Close()

	// Calculate checksum
	hash := sha256.Sum256(data)
	checksum := fmt.Sprintf("%x", hash)

	// Get storage backend
	backend, exists := c.storageBackends[storage.Type]
	if !exists {
		return fmt.Errorf("storage backend %s not found", storage.Type)
	}

	// Determine storage key
	storageKey := c.getStorageKey(sessionID, state.CheckpointID, storage)

	// Save to storage
	if err := backend.Save(storageKey, compressedData.Bytes()); err != nil {
		return fmt.Errorf("failed to save to storage: %v", err)
	}

	// Store locally
	c.sessionStates[sessionID] = state

	// Update checkpoint status
	for key, cp := range c.checkpoints {
		if cp.Spec.SessionID == sessionID {
			cp.Status.Phase = types.PhaseSucceeded
			cp.Status.Size = int64(len(compressedData.Bytes()))
			cp.Status.Location = storageKey
			cp.Status.Checksum = checksum
			cp.Status.CompletedAt = time.Now()
			c.checkpoints[key] = cp
			break
		}
	}

	return nil
}

// RestoreSessionState restores session state from storage
func (c *CheckpointController) RestoreSessionState(ctx context.Context, sessionID, checkpointID string, storage types.CheckpointStorage) (*types.SessionState, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	// Get storage backend
	backend, exists := c.storageBackends[storage.Type]
	if !exists {
		return nil, fmt.Errorf("storage backend %s not found", storage.Type)
	}

	// Determine storage key
	storageKey := c.getStorageKey(sessionID, checkpointID, storage)

	// Load from storage
	compressedData, err := backend.Load(storageKey)
	if err != nil {
		return nil, fmt.Errorf("failed to load from storage: %v", err)
	}

	// Decompress data
	gzipReader, err := gzip.NewReader(bytes.NewReader(compressedData))
	if err != nil {
		return nil, fmt.Errorf("failed to decompress state: %v", err)
	}
	defer gzipReader.Close()

	data, err := io.ReadAll(gzipReader)
	if err != nil {
		return nil, fmt.Errorf("failed to read decompressed state: %v", err)
	}

	// Deserialize state
	state := &types.SessionState{}
	if err := state.FromJSON(data); err != nil {
		return nil, fmt.Errorf("failed to deserialize state: %v", err)
	}

	// Verify checksum
	hash := sha256.Sum256(data)
	checksum := fmt.Sprintf("%x", hash)

	for _, cp := range c.checkpoints {
		if cp.Spec.SessionID == sessionID && cp.Metadata.Name == checkpointID {
			if cp.Status.Checksum != "" && cp.Status.Checksum != checksum {
				return nil, fmt.Errorf("checksum mismatch: expected %s, got %s", cp.Status.Checksum, checksum)
			}
			break
		}
	}

	c.sessionStates[sessionID] = state

	return state, nil
}

// ListCheckpoints lists checkpoints for a session
func (c *CheckpointController) ListCheckpoints(sessionID string) []*types.Checkpoint {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.Checkpoint
	for _, cp := range c.checkpoints {
		if cp.Spec.SessionID == sessionID {
			result = append(result, cp)
		}
	}

	return result
}

// GetCheckpoint gets a checkpoint
func (c *CheckpointController) GetCheckpoint(namespace, name string) (*types.Checkpoint, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	checkpoint, exists := c.checkpoints[key]
	if !exists {
		return nil, fmt.Errorf("checkpoint %s not found", key)
	}

	return checkpoint, nil
}

// DeleteCheckpoint deletes a checkpoint
func (c *CheckpointController) DeleteCheckpoint(namespace, name string, storage types.CheckpointStorage) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	checkpoint, exists := c.checkpoints[key]
	if !exists {
		return fmt.Errorf("checkpoint %s not found", key)
	}

	// Delete from storage
	if backend, ok := c.storageBackends[storage.Type]; ok {
		storageKey := checkpoint.Status.Location
		if storageKey != "" {
			if err := backend.Delete(storageKey); err != nil {
				return fmt.Errorf("failed to delete from storage: %v", err)
			}
		}
	}

	delete(c.checkpoints, key)

	return nil
}

// CleanupOldCheckpoints removes old checkpoints based on retention policy
func (c *CheckpointController) CleanupOldCheckpoints(sessionID string, policy types.CheckpointRetentionPolicy, storage types.CheckpointStorage) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	// Get checkpoints for session
	var sessionCheckpoints []*types.Checkpoint
	for _, cp := range c.checkpoints {
		if cp.Spec.SessionID == sessionID {
			sessionCheckpoints = append(sessionCheckpoints, cp)
		}
	}

	// Sort by completion time (oldest first)
	// Simplified: just use index order for now

	toDelete := []string{}
	for _, cp := range sessionCheckpoints {
		if cp.ShouldDelete(policy, len(sessionCheckpoints)) {
			toDelete = append(toDelete, fmt.Sprintf("%s/%s", cp.Metadata.Namespace, cp.Metadata.Name))
		}
	}

	// Delete checkpoints
	for _, key := range toDelete {
		if cp, exists := c.checkpoints[key]; exists {
			if backend, ok := c.storageBackends[storage.Type]; ok {
				if cp.Status.Location != "" {
					backend.Delete(cp.Status.Location)
				}
			}
			delete(c.checkpoints, key)
		}
	}

	return nil
}

// RecoverSession recovers a session from a checkpoint
func (c *CheckpointController) RecoverSession(ctx context.Context, req *types.RecoveryRequest, storage types.CheckpointStorage) (*types.RecoveryResult, error) {
	startTime := time.Now()

	result := &types.RecoveryResult{
		SessionID:    req.SessionID,
		CheckpointID: req.CheckpointID,
	}

	// If no checkpoint specified, use the latest
	checkpointID := req.CheckpointID
	if checkpointID == "" {
		checkpoints := c.ListCheckpoints(req.SessionID)
		if len(checkpoints) > 0 {
			// Get the most recent
			checkpointID = checkpoints[len(checkpoints)-1].Metadata.Name
		}
	}

	if checkpointID == "" {
		result.Success = false
		result.ErrorMessage = "no checkpoint found for session"
		result.CompletedAt = time.Now()
		result.DurationMs = time.Since(startTime).Milliseconds()
		return result, nil
	}

	// Restore session state
	state, err := c.RestoreSessionState(ctx, req.SessionID, checkpointID, storage)
	if err != nil {
		result.Success = false
		result.ErrorMessage = err.Error()
		result.CompletedAt = time.Now()
		result.DurationMs = time.Since(startTime).Milliseconds()
		return result, nil
	}

	// Mark as successful (in real implementation, would create new pod)
	result.Success = true
	result.NewPodName = fmt.Sprintf("%s-recovered", req.SessionID)
	result.CheckpointID = checkpointID
	result.CompletedAt = time.Now()
	result.DurationMs = time.Since(startTime).Milliseconds()

	_ = state // Use state for recovery

	return result, nil
}

// getStorageKey generates a storage key for checkpoint
func (c *CheckpointController) getStorageKey(sessionID, checkpointID string, storage types.CheckpointStorage) string {
	var prefix string
	switch storage.Type {
	case "s3":
		if storage.S3 != nil {
			prefix = storage.S3.Prefix
		}
	case "gcs":
		if storage.GCS != nil {
			prefix = storage.GCS.Prefix
		}
	case "pvc":
		if storage.PVC != nil {
			prefix = storage.PVC.Path
		}
	}

	return fmt.Sprintf("%s/%s/%s.json.gz", prefix, sessionID, checkpointID)
}

// SerializeState serializes session state to JSON
func (c *CheckpointController) SerializeState(state *types.SessionState) ([]byte, error) {
	return json.Marshal(state)
}

// DeserializeState deserializes session state from JSON
func (c *CheckpointController) DeserializeState(data []byte) (*types.SessionState, error) {
	state := &types.SessionState{}
	if err := json.Unmarshal(data, state); err != nil {
		return nil, err
	}
	return state, nil
}

// InMemoryStorageBackend implements an in-memory storage backend for testing
type InMemoryStorageBackend struct {
	data map[string][]byte
	mu   sync.RWMutex
}

// NewInMemoryStorageBackend creates a new in-memory storage backend
func NewInMemoryStorageBackend() *InMemoryStorageBackend {
	return &InMemoryStorageBackend{
		data: make(map[string][]byte),
	}
}

// Save saves data to memory
func (b *InMemoryStorageBackend) Save(key string, data []byte) error {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.data[key] = data
	return nil
}

// Load loads data from memory
func (b *InMemoryStorageBackend) Load(key string) ([]byte, error) {
	b.mu.RLock()
	defer b.mu.RUnlock()
	data, exists := b.data[key]
	if !exists {
		return nil, fmt.Errorf("key %s not found", key)
	}
	return data, nil
}

// Delete deletes data from memory
func (b *InMemoryStorageBackend) Delete(key string) error {
	b.mu.Lock()
	defer b.mu.Unlock()
	delete(b.data, key)
	return nil
}

// List lists keys with prefix
func (b *InMemoryStorageBackend) List(prefix string) ([]string, error) {
	b.mu.RLock()
	defer b.mu.RUnlock()

	var result []string
	for key := range b.data {
		if len(key) >= len(prefix) && key[:len(prefix)] == prefix {
			result = append(result, key)
		}
	}

	return result, nil
}

package controllers

import (
	"context"
	"fmt"
	"sync"
	"time"

	"github.com/volcengine/agentcube/pkg/types"
)

// QuotaController manages resource quotas
type QuotaController struct {
	quotas      map[string]*types.ResourceQuota
	usage       map[string]types.ResourceUsage
	mu          sync.RWMutex
	stopCh      chan struct{}
	reconcileInterval time.Duration
}

// NewQuotaController creates a new quota controller
func NewQuotaController() *QuotaController {
	return &QuotaController{
		quotas:            make(map[string]*types.ResourceQuota),
		usage:             make(map[string]types.ResourceUsage),
		stopCh:            make(chan struct{}),
		reconcileInterval: 60 * time.Second,
	}
}

// Start starts the quota controller
func (c *QuotaController) Start() {
	go c.reconcileLoop()
}

// Stop stops the quota controller
func (c *QuotaController) Stop() {
	close(c.stopCh)
}

// reconcileLoop runs the reconciliation loop
func (c *QuotaController) reconcileLoop() {
	ticker := time.NewTicker(c.reconcileInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			c.Reconcile()
		case <-c.stopCh:
			return
		}
	}
}

// Reconcile reconciles quota usage
func (c *QuotaController) Reconcile() {
	c.mu.Lock()
	defer c.mu.Unlock()

	for key, quota := range c.quotas {
		usage, exists := c.usage[key]
		if exists {
			quota.Status.Used = usage
			quota.Status.LastSyncTime = time.Now()

			// Calculate remaining
			quota.Status.Remaining.SessionsCount = quota.Spec.Hard.SessionsCount - usage.SessionsCount
			if quota.Status.Remaining.SessionsCount < 0 {
				quota.Status.Remaining.SessionsCount = 0
			}
		}
	}
}

// CreateQuota creates a new resource quota
func (c *QuotaController) CreateQuota(ctx context.Context, quota *types.ResourceQuota) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", quota.Metadata.Namespace, quota.Metadata.Name)

	if _, exists := c.quotas[key]; exists {
		return fmt.Errorf("quota %s already exists", key)
	}

	errors := quota.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	c.quotas[key] = quota
	c.usage[key] = types.ResourceUsage{
		SessionsCount: 0,
	}

	return nil
}

// GetQuota gets a resource quota
func (c *QuotaController) GetQuota(namespace, name string) (*types.ResourceQuota, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	quota, exists := c.quotas[key]
	if !exists {
		return nil, fmt.Errorf("quota %s not found", key)
	}

	return quota, nil
}

// UpdateQuota updates a resource quota
func (c *QuotaController) UpdateQuota(ctx context.Context, quota *types.ResourceQuota) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", quota.Metadata.Namespace, quota.Metadata.Name)

	if _, exists := c.quotas[key]; !exists {
		return fmt.Errorf("quota %s not found", key)
	}

	errors := quota.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	c.quotas[key] = quota
	return nil
}

// DeleteQuota deletes a resource quota
func (c *QuotaController) DeleteQuota(namespace, name string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)

	if _, exists := c.quotas[key]; !exists {
		return fmt.Errorf("quota %s not found", key)
	}

	delete(c.quotas, key)
	delete(c.usage, key)

	return nil
}

// ListQuotas lists all quotas in a namespace
func (c *QuotaController) ListQuotas(namespace string) []*types.ResourceQuota {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.ResourceQuota
	for key, quota := range c.quotas {
		if quota.Metadata.Namespace == namespace {
			result = append(result, quota)
		}
	}

	return result
}

// CanCreateSession checks if a session can be created within quota
func (c *QuotaController) CanCreateSession(namespace, sessionType string) (*types.QuotaViolation, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	// Find quota for namespace (first match)
	for key, quota := range c.quotas {
		if quota.Metadata.Namespace == namespace {
			usage := c.usage[key]
			violation := quota.CanCreateSession(usage, sessionType)
			return violation, nil
		}
	}

	return nil, nil // No quota defined, allow
}

// UpdateUsage updates resource usage
func (c *QuotaController) UpdateUsage(namespace string, delta int) {
	c.mu.Lock()
	defer c.mu.Unlock()

	for key, quota := range c.quotas {
		if quota.Metadata.Namespace == namespace {
			usage := c.usage[key]
			usage.SessionsCount += delta
			if usage.SessionsCount < 0 {
				usage.SessionsCount = 0
			}
			c.usage[key] = usage
		}
	}
}

// GetMetrics returns quota metrics
func (c *QuotaController) GetMetrics(namespace, name string) *types.QuotaMetrics {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	quota, exists := c.quotas[key]
	if !exists {
		return nil
	}

	usage := c.usage[key]
	utilization := 0.0
	if quota.Spec.Hard.SessionsCount > 0 {
		utilization = float64(usage.SessionsCount) / float64(quota.Spec.Hard.SessionsCount) * 100
	}

	return &types.QuotaMetrics{
		Namespace:   namespace,
		QuotaName:   name,
		ResourceType: "sessions",
		Used:        float64(usage.SessionsCount),
		Limit:       float64(quota.Spec.Hard.SessionsCount),
		Utilization: utilization,
		LastSyncTime: quota.Status.LastSyncTime,
	}
}

package controllers

import (
	"context"
	"fmt"
	"sync"

	"github.com/volcengine/agentcube/pkg/types"
)

// TenantController manages tenants
type TenantController struct {
	tenants       map[string]*types.Tenant
	policies      map[string]*types.TenantAccessPolicy
	mu            sync.RWMutex
}

// NewTenantController creates a new tenant controller
func NewTenantController() *TenantController {
	return &TenantController{
		tenants:  make(map[string]*types.Tenant),
		policies: make(map[string]*types.TenantAccessPolicy),
	}
}

// CreateTenant creates a new tenant
func (c *TenantController) CreateTenant(ctx context.Context, tenant *types.Tenant) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	if _, exists := c.tenants[tenant.Metadata.Name]; exists {
		return fmt.Errorf("tenant %s already exists", tenant.Metadata.Name)
	}

	errors := tenant.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	tenant.Status.Phase = types.PhasePending
	c.tenants[tenant.Metadata.Name] = tenant

	return nil
}

// GetTenant gets a tenant
func (c *TenantController) GetTenant(name string) (*types.Tenant, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	tenant, exists := c.tenants[name]
	if !exists {
		return nil, fmt.Errorf("tenant %s not found", name)
	}

	return tenant, nil
}

// UpdateTenant updates a tenant
func (c *TenantController) UpdateTenant(ctx context.Context, tenant *types.Tenant) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	if _, exists := c.tenants[tenant.Metadata.Name]; !exists {
		return fmt.Errorf("tenant %s not found", tenant.Metadata.Name)
	}

	errors := tenant.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	c.tenants[tenant.Metadata.Name] = tenant
	return nil
}

// DeleteTenant deletes a tenant
func (c *TenantController) DeleteTenant(name string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	if _, exists := c.tenants[name]; !exists {
		return fmt.Errorf("tenant %s not found", name)
	}

	delete(c.tenants, name)

	// Delete associated policies
	for key, policy := range c.policies {
		if policy.Spec.SourceTenant == name || policy.Spec.TargetTenant == name {
			delete(c.policies, key)
		}
	}

	return nil
}

// ListTenants lists all tenants
func (c *TenantController) ListTenants() []*types.Tenant {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.Tenant
	for _, tenant := range c.tenants {
		result = append(result, tenant)
	}

	return result
}

// IsNamespaceIsolated checks if a namespace is isolated within a tenant
func (c *TenantController) IsNamespaceIsolated(tenantName, namespace string) bool {
	c.mu.RLock()
	defer c.mu.RUnlock()

	tenant, exists := c.tenants[tenantName]
	if !exists {
		return false
	}

	return tenant.IsResourceIsolated(namespace)
}

// CanAccessTenant checks if source tenant can access target tenant
func (c *TenantController) CanAccessTenant(sourceTenant, targetTenant, operation, namespace, name string) bool {
	c.mu.RLock()
	defer c.mu.RUnlock()

	for _, policy := range c.policies {
		if policy.CanAccess(sourceTenant, targetTenant, operation, namespace, name) {
			return true
		}
	}

	return false
}

// CreateAccessPolicy creates a tenant access policy
func (c *TenantController) CreateAccessPolicy(ctx context.Context, policy *types.TenantAccessPolicy) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", policy.Metadata.Namespace, policy.Metadata.Name)

	if _, exists := c.policies[key]; exists {
		return fmt.Errorf("policy %s already exists", key)
	}

	policy.Status.Phase = types.PhasePending
	c.policies[key] = policy

	return nil
}

// GetTenantNamespaces gets all namespaces for a tenant
func (c *TenantController) GetTenantNamespaces(tenantName string) []string {
	c.mu.RLock()
	defer c.mu.RUnlock()

	tenant, exists := c.tenants[tenantName]
	if !exists {
		return nil
	}

	return tenant.Spec.Namespaces
}

// IsAdmin checks if user is a tenant admin
func (c *TenantController) IsAdmin(tenantName, user string) bool {
	c.mu.RLock()
	defer c.mu.RUnlock()

	tenant, exists := c.tenants[tenantName]
	if !exists {
		return false
	}

	for _, admin := range tenant.Spec.Admins {
		if admin == user {
			return true
		}
	}

	return false
}

// GetTenantNetworkPolicy gets network policy for a tenant
func (c *TenantController) GetTenantNetworkPolicy(tenantName string) *types.NetworkIsolation {
	c.mu.RLock()
	defer c.mu.RUnlock()

	tenant, exists := c.tenants[tenantName]
	if !exists {
		return nil
	}

	return &tenant.Spec.Isolation.Network
}

// UpdateActiveSessions updates the active session count for a tenant
func (c *TenantController) UpdateActiveSessions(tenantName string, delta int) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if tenant, exists := c.tenants[tenantName]; exists {
		tenant.Status.ActiveSessions += delta
		if tenant.Status.ActiveSessions < 0 {
			tenant.Status.ActiveSessions = 0
		}
	}
}

package controllers

import (
	"context"
	"fmt"
	"sync"
	"time"

	"github.com/volcengine/agentcube/pkg/types"
)

// AutoscalerController manages autoscalers
type AutoscalerController struct {
	autoscalers    map[string]*types.SandboxAutoscaler
	schedules      map[string]*types.ScalingSchedule
	history        []types.ScalingEvent
	sessionReplicas map[string]int32
	mu             sync.RWMutex
}

// NewAutoscalerController creates a new autoscaler controller
func NewAutoscalerController() *AutoscalerController {
	return &AutoscalerController{
		autoscalers:     make(map[string]*types.SandboxAutoscaler),
		schedules:       make(map[string]*types.ScalingSchedule),
		history:         make([]types.ScalingEvent, 0),
		sessionReplicas: make(map[string]int32),
	}
}

// CreateAutoscaler creates a new autoscaler
func (c *AutoscalerController) CreateAutoscaler(ctx context.Context, autoscaler *types.SandboxAutoscaler) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", autoscaler.Metadata.Namespace, autoscaler.Metadata.Name)

	if _, exists := c.autoscalers[key]; exists {
		return fmt.Errorf("autoscaler %s already exists", key)
	}

	errors := autoscaler.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	autoscaler.Status.Phase = types.PhasePending
	autoscaler.Status.CurrentReplicas = autoscaler.Spec.MinReplicas
	c.autoscalers[key] = autoscaler

	return nil
}

// GetAutoscaler gets an autoscaler
func (c *AutoscalerController) GetAutoscaler(namespace, name string) (*types.SandboxAutoscaler, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	autoscaler, exists := c.autoscalers[key]
	if !exists {
		return nil, fmt.Errorf("autoscaler %s not found", key)
	}

	return autoscaler, nil
}

// UpdateAutoscaler updates an autoscaler
func (c *AutoscalerController) UpdateAutoscaler(ctx context.Context, autoscaler *types.SandboxAutoscaler) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", autoscaler.Metadata.Namespace, autoscaler.Metadata.Name)

	if _, exists := c.autoscalers[key]; !exists {
		return fmt.Errorf("autoscaler %s not found", key)
	}

	errors := autoscaler.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	c.autoscalers[key] = autoscaler
	return nil
}

// DeleteAutoscaler deletes an autoscaler
func (c *AutoscalerController) DeleteAutoscaler(namespace, name string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)

	if _, exists := c.autoscalers[key]; !exists {
		return fmt.Errorf("autoscaler %s not found", key)
	}

	delete(c.autoscalers, key)
	return nil
}

// EvaluateScaling evaluates scaling decision for an autoscaler
func (c *AutoscalerController) EvaluateScaling(namespace, name string, metrics map[string]float64) (int32, bool, string) {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	autoscaler, exists := c.autoscalers[key]
	if !exists {
		return 0, false, "autoscaler not found"
	}

	currentReplicas := autoscaler.Status.CurrentReplicas
	newReplicas, shouldScale := autoscaler.ShouldScale(currentReplicas, metrics)

	reason := ""
	if shouldScale {
		if newReplicas > currentReplicas {
			reason = "scale_up"
		} else if newReplicas < currentReplicas {
			reason = "scale_down"
		}
	}

	return newReplicas, shouldScale, reason
}

// ApplyScaling applies scaling to an autoscaler
func (c *AutoscalerController) ApplyScaling(namespace, name string, newReplicas int32, reason string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	autoscaler, exists := c.autoscalers[key]
	if !exists {
		return fmt.Errorf("autoscaler %s not found", key)
	}

	oldReplicas := autoscaler.Status.CurrentReplicas
	autoscaler.Status.CurrentReplicas = newReplicas
	autoscaler.Status.DesiredReplicas = newReplicas
	now := time.Now().Format(time.RFC3339)
	autoscaler.Status.LastScaleTime = &now

	// Record event
	event := types.ScalingEvent{
		Timestamp:      now,
		AutoscalerName: name,
		Namespace:      namespace,
		OldReplicas:    oldReplicas,
		NewReplicas:    newReplicas,
		Reason:         reason,
		Message:        fmt.Sprintf("Scaled from %d to %d replicas", oldReplicas, newReplicas),
	}
	c.history = append(c.history, event)

	// Keep only last 1000 events
	if len(c.history) > 1000 {
		c.history = c.history[len(c.history)-1000:]
	}

	return nil
}

// GetScalingHistory gets scaling history for an autoscaler
func (c *AutoscalerController) GetScalingHistory(namespace, name string, limit int) []types.ScalingEvent {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []types.ScalingEvent
	for i := len(c.history) - 1; i >= 0 && len(result) < limit; i-- {
		event := c.history[i]
		if event.Namespace == namespace && event.AutoscalerName == name {
			result = append(result, event)
		}
	}

	return result
}

// CreateSchedule creates a scaling schedule
func (c *AutoscalerController) CreateSchedule(ctx context.Context, schedule *types.ScalingSchedule) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", schedule.Metadata.Namespace, schedule.Metadata.Name)

	if _, exists := c.schedules[key]; exists {
		return fmt.Errorf("schedule %s already exists", key)
	}

	schedule.Status.Phase = types.PhasePending
	c.schedules[key] = schedule

	return nil
}

// EvaluateSchedules evaluates all schedules and returns active ones
func (c *AutoscalerController) EvaluateSchedules() map[string]int32 {
	c.mu.RLock()
	defer c.mu.RUnlock()

	result := make(map[string]int32)
	now := time.Now()

	for key, schedule := range c.schedules {
		for _, rule := range schedule.Spec.Schedules {
			// Simple check: if we're in the schedule window
			// In real implementation, would parse cron expression
			_ = rule
			_ = now
			result[key] = rule.MinReplicas
		}
	}

	return result
}

// SetSessionReplicas sets the replica count for a session
func (c *AutoscalerController) SetSessionReplicas(sessionID string, replicas int32) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.sessionReplicas[sessionID] = replicas
}

// GetSessionReplicas gets the replica count for a session
func (c *AutoscalerController) GetSessionReplicas(sessionID string) int32 {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.sessionReplicas[sessionID]
}

