import (
	"context"
	"fmt"
	"sync"
	"time"

	"github.com/volcengine/agentcube/pkg/types"
)

// PolicyController manages policies
type PolicyController struct {
	policies    map[string]*types.Policy
	bindings    map[string]*types.PolicyBinding
	engine      types.PolicyEngine
	mu          sync.RWMutex
}

// NewPolicyController creates a new policy controller
func NewPolicyController(engine types.PolicyEngine) *PolicyController {
	return &PolicyController{
		policies: make(map[string]*types.Policy),
		bindings: make(map[string]*types.PolicyBinding),
		engine:   engine,
	}
}

// CreatePolicy creates a new policy
func (c *PolicyController) CreatePolicy(ctx context.Context, policy *types.Policy) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", policy.Metadata.Namespace, policy.Metadata.Name)

	if _, exists := c.policies[key]; exists {
		return fmt.Errorf("policy %s already exists", key)
	}

	errors := policy.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	// Validate conditions
	for _, rule := range policy.Spec.Rules {
		if c.engine != nil {
			if err := c.engine.ValidateCondition(rule.Condition); err != nil {
				return fmt.Errorf("invalid condition in rule %s: %v", rule.Name, err)
			}
		}
	}

	policy.Status.Phase = types.PhasePending
	c.policies[key] = policy

	return nil
}

// GetPolicy gets a policy
func (c *PolicyController) GetPolicy(namespace, name string) (*types.Policy, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	policy, exists := c.policies[key]
	if !exists {
		return nil, fmt.Errorf("policy %s not found", key)
	}

	return policy, nil
}

// UpdatePolicy updates a policy
func (c *PolicyController) UpdatePolicy(ctx context.Context, policy *types.Policy) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", policy.Metadata.Namespace, policy.Metadata.Name)

	if _, exists := c.policies[key]; !exists {
		return fmt.Errorf("policy %s not found", key)
	}

	errors := policy.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	// Validate conditions
	for _, rule := range policy.Spec.Rules {
		if c.engine != nil {
			if err := c.engine.ValidateCondition(rule.Condition); err != nil {
				return fmt.Errorf("invalid condition in rule %s: %v", rule.Name, err)
			}
		}
	}

	c.policies[key] = policy
	return nil
}

// DeletePolicy deletes a policy
func (c *PolicyController) DeletePolicy(namespace, name string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)

	if _, exists := c.policies[key]; !exists {
		return fmt.Errorf("policy %s not found", key)
	}

	delete(c.policies, key)

	// Delete associated bindings
	for bKey, binding := range c.bindings {
		if binding.Spec.PolicyRef == name {
			delete(c.bindings, bKey)
		}
	}

	return nil
}

// ListPolicies lists all policies
func (c *PolicyController) ListPolicies(namespace string) []*types.Policy {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.Policy
	for _, policy := range c.policies {
		if namespace == "" || policy.Metadata.Namespace == namespace {
			result = append(result, policy)
		}
	}

	return result
}

// Evaluate evaluates a resource against all applicable policies
func (c *PolicyController) Evaluate(ctx context.Context, resource interface{}, action types.Action, namespace string) (*types.EvaluationResult, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	if c.engine == nil {
		return &types.EvaluationResult{Allowed: true}, nil
	}

	result := &types.EvaluationResult{
		Allowed:    true,
		Violations: make([]types.Violation, 0),
		Warnings:   make([]string, 0),
	}

	for _, policy := range c.policies {
		// Only evaluate policies in the same namespace or cluster-scoped
		if policy.Metadata.Namespace != "" && policy.Metadata.Namespace != namespace {
			continue
		}

		policyResult, err := c.engine.Evaluate(resource, action)
		if err != nil {
			return nil, fmt.Errorf("failed to evaluate policy %s: %v", policy.Metadata.Name, err)
		}

		// Merge results
		if !policyResult.Allowed && policy.Spec.Enforcement == types.EnforcementModeEnforce {
			result.Allowed = false
		}

		for _, v := range policyResult.Violations {
			violation := types.Violation{
				RuleName: policy.Metadata.Name + "/" + v.RuleName,
				Message:  v.Message,
			}
			result.Violations = append(result.Violations, violation)

			// Add to policy status
			if policy.Spec.Enforcement == types.EnforcementModeEnforce {
				policy.AddViolation(types.PolicyViolation{
					RuleName:  v.RuleName,
					Resource:  namespace,
					Message:   v.Message,
					Timestamp: time.Now().Format(time.RFC3339),
					Action:    string(action),
				})
			}
		}

		result.Warnings = append(result.Warnings, policyResult.Warnings...)
	}

	return result, nil
}

// GetViolations gets violations for a policy
func (c *PolicyController) GetViolations(namespace, name string) []types.PolicyViolation {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	policy, exists := c.policies[key]
	if !exists {
		return nil
	}

	return policy.Status.Violations
}

// CreateBinding creates a policy binding
func (c *PolicyController) CreateBinding(ctx context.Context, binding *types.PolicyBinding) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", binding.Metadata.Namespace, binding.Metadata.Name)

	if _, exists := c.bindings[key]; exists {
		return fmt.Errorf("binding %s already exists", key)
	}

	c.bindings[key] = binding
	return nil
}

// ClearViolations clears all violations for a policy
func (c *PolicyController) ClearViolations(namespace, name string) {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	if policy, exists := c.policies[key]; exists {
		policy.ClearViolations()
	}
}

// SimplePolicyEngine implements a simple policy engine
type SimplePolicyEngine struct {
	mu sync.RWMutex
}

// NewSimplePolicyEngine creates a new simple policy engine
func NewSimplePolicyEngine() *SimplePolicyEngine {
	return &SimplePolicyEngine{}
}

// Evaluate evaluates a resource against policies
func (e *SimplePolicyEngine) Evaluate(resource interface{}, action types.Action) (*types.EvaluationResult, error) {
	// Simplified evaluation - in real implementation would use CEL
	return &types.EvaluationResult{
		Allowed:    true,
		Violations: []types.Violation{},
		Warnings:   []string{},
	}, nil
}

// ValidateCondition validates a CEL condition
func (e *SimplePolicyEngine) ValidateCondition(condition string) error {
	// Simplified validation
	if condition == "" {
		return fmt.Errorf("condition cannot be empty")
	}
	return nil
}

