}

// GetRestore gets a restore
func (c *BackupController) GetRestore(namespace, name string) (*types.Restore, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	restore, exists := c.restores[key]
	if !exists {
		return nil, fmt.Errorf("restore %s not found", key)
	}

	return restore, nil
}

// UpdateRestore updates restore status
func (c *BackupController) UpdateRestore(ctx context.Context, restore *types.Restore) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", restore.Metadata.Namespace, restore.Metadata.Name)

	if _, exists := c.restores[key]; !exists {
		return fmt.Errorf("restore %s not found", key)
	}

	c.restores[key] = restore
	return nil
}

// ListRestores lists restores in a namespace
func (c *BackupController) ListRestores(namespace string) []*types.Restore {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.Restore
	for _, restore := range c.restores {
		if restore.Metadata.Namespace == namespace {
			result = append(result, restore)
		}
	}

	return result
}

// ExecuteBackup executes a backup
func (c *BackupController) ExecuteBackup(ctx context.Context, namespace, name string) (*types.BackupResult, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	backup, exists := c.backups[key]
	if !exists {
		return nil, fmt.Errorf("backup %s not found", key)
	}

	result := &types.BackupResult{
		BackupName: backup.Metadata.Name,
		StartTime:  time.Now(),
	}

	// Simulate backup
	backup.Status.Phase = types.PhaseRunning

	// In real implementation, would actually backup resources
	// For now, just mark as succeeded
	backup.Status.Phase = types.PhaseSucceeded
	backup.Status.CompletionTime = time.Now().Format(time.RFC3339)
	backup.Status.Size = 1024 * 1024 // 1MB dummy size
	result.Success = true
	result.ItemsBackedUp = len(backup.Spec.Resources)
	result.TotalSize = backup.Status.Size
	result.DurationMs = 1000

	return result, nil
}

// ExecuteRestore executes a restore
func (c *BackupController) ExecuteRestore(ctx context.Context, namespace, name string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	restore, exists := c.restores[key]
	if !exists {
		return fmt.Errorf("restore %s not found", key)
	}

	// Check if backup exists
	backupKey := fmt.Sprintf("%s/%s", restore.Spec.BackupRef.Namespace, restore.Spec.BackupRef.Name)
	backup, exists := c.backups[backupKey]
	if !exists {
		return fmt.Errorf("backup %s not found", backupKey)
	}

	// Simulate restore
	restore.Status.Phase = types.PhaseRunning

	// In real implementation, would actually restore resources
	// For now, just mark as succeeded
	restore.Status.Phase = types.PhaseSucceeded
	restore.Status.CompletionTime = time.Now().Format(time.RFC3339)
	restore.Status.RestoredCount = len(backup.Spec.Resources)

	return nil
}

// CleanupOldBackups removes old backups based on retention policy
func (c *BackupController) CleanupOldBackups(namespace string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	now := time.Now()

	for key, backup := range c.backups {
		if backup.Metadata.Namespace != namespace {
			continue
		}

		// Check count-based retention
		namespaceBackups := 0
		for _, b := range c.backups {
			if b.Metadata.Namespace == namespace {
				namespaceBackups++
			}
		}

		if backup.Spec.Retention.Count > 0 && namespaceBackups > backup.Spec.Retention.Count {
			delete(c.backups, key)
			continue
		}

		// Check age-based retention
		if backup.Spec.Retention.Age != "" {
			// Parse duration
			duration, _ := time.ParseDuration(backup.Spec.Retention.Age)
			if duration > 0 {
				completionTime, _ := time.Parse(time.RFC3339, backup.Status.CompletionTime)
				if !completionTime.IsZero() && now.Sub(completionTime) > duration {
					delete(c.backups, key)
				}
			}
		}
	}

	return nil
}

