// GetAuditRetention gets audit retention configuration
func (c *ComplianceController) GetAuditRetention(namespace, name string) (*types.AuditRetention, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.auditConfigs[key]
	if !exists {
		return nil, fmt.Errorf("audit config %s not found", key)
	}

	return &config.Spec.Retention, nil
}

// CleanupOldAuditLogs removes old audit logs based on retention policy
func (c *ComplianceController) CleanupOldAuditLogs() error {
	c.mu.Lock()
	defer c.mu.Unlock()

	now := time.Now()

	for _, config := range c.auditConfigs {
		retention, _ := time.ParseDuration(config.Spec.Retention.Duration)
		if retention > 0 {
			newLogs := make([]types.AuditEvent, 0)
			for _, log := range c.auditLogs {
				logTime, _ := time.Parse(time.RFC3339, log.Timestamp)
				if now.Sub(logTime) <= retention {
					newLogs = append(newLogs, log)
				}
			}
			c.auditLogs = newLogs
		}
	}

	return nil
}

// ExportAuditLogs exports audit logs
func (c *ComplianceController) ExportAuditLogs(namespace string, startTime, endTime string) ([]types.AuditEvent, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	start, _ := time.Parse(time.RFC3339, startTime)
	end, _ := time.Parse(time.RFC3339, endTime)

	var result []types.AuditEvent
	for _, event := range c.auditLogs {
		eventTime, _ := time.Parse(time.RFC3339, event.Timestamp)

		if namespace != "" && event.Namespace != namespace {
			continue
		}

		if !eventTime.Before(start) && !eventTime.After(end) {
			result = append(result, event)
		}
	}

	return result, nil
}

package controllers

import (
	"context"
	"fmt"
	"sync"

	"github.com/volcengine/agentcube/pkg/types"
)

// MeshController manages service mesh configurations
type MeshController struct {
	configurations map[string]*types.MeshConfiguration
	mu             sync.RWMutex
}

// NewMeshController creates a new mesh controller
func NewMeshController() *MeshController {
	return &MeshController{
		configurations: make(map[string]*types.MeshConfiguration),
	}
}

// CreateConfiguration creates a new mesh configuration
func (c *MeshController) CreateConfiguration(ctx context.Context, config *types.MeshConfiguration) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", config.Metadata.Namespace, config.Metadata.Name)

	if _, exists := c.configurations[key]; exists {
		return fmt.Errorf("mesh configuration %s already exists", key)
	}

	errors := config.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	config.Status.Phase = types.PhasePending
	config.Status.SidecarCount = 0
	c.configurations[key] = config

	return nil
}

// GetConfiguration gets a mesh configuration
func (c *MeshController) GetConfiguration(namespace, name string) (*types.MeshConfiguration, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.configurations[key]
	if !exists {
		return nil, fmt.Errorf("mesh configuration %s not found", key)
	}

	return config, nil
}

// UpdateConfiguration updates a mesh configuration
func (c *MeshController) UpdateConfiguration(ctx context.Context, config *types.MeshConfiguration) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", config.Metadata.Namespace, config.Metadata.Name)

	if _, exists := c.configurations[key]; !exists {
		return fmt.Errorf("mesh configuration %s not found", key)
	}

	errors := config.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	c.configurations[key] = config
	return nil
}

// DeleteConfiguration deletes a mesh configuration
func (c *MeshController) DeleteConfiguration(namespace, name string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)

	if _, exists := c.configurations[key]; !exists {
		return fmt.Errorf("mesh configuration %s not found", key)
	}

	delete(c.configurations, key)
	return nil
}

// ListConfigurations lists mesh configurations
func (c *MeshController) ListConfigurations(namespace string) []*types.MeshConfiguration {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.MeshConfiguration
	for _, config := range c.configurations {
		if namespace == "" || config.Metadata.Namespace == namespace {
			result = append(result, config)
		}
	}

	return result
}

// GetSidecarAnnotation returns sidecar injection annotation for a configuration
func (c *MeshController) GetSidecarAnnotation(namespace, name string) (string, string, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.configurations[key]
	if !exists {
		return "", "", fmt.Errorf("mesh configuration %s not found", key)
	}

	annotation, value := config.GetSidecarAnnotation()
	return annotation, value, nil
}

// IsCompatible checks if configuration is compatible with runtime
func (c *MeshController) IsCompatible(namespace, name, runtimeType string) (bool, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.configurations[key]
	if !exists {
		return false, fmt.Errorf("mesh configuration %s not found", key)
	}

	return config.IsCompatibleWith(runtimeType), nil
}

// UpdateSidecarCount updates sidecar count for a configuration
func (c *MeshController) UpdateSidecarCount(namespace, name string, count int) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.configurations[key]
	if !exists {
		return fmt.Errorf("mesh configuration %s not found", key)
	}

	config.Status.SidecarCount = count
	return nil
}

// GetMTLSMode returns mTLS mode for a configuration
func (c *MeshController) GetMTLSMode(namespace, name string) (types.MTLSMode, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.configurations[key]
	if !exists {
		return "", fmt.Errorf("mesh configuration %s not found", key)
	}

	return config.Spec.MTLS.Mode, nil
}

// GenerateTrafficPolicy generates traffic policy for a runtime
func (c *MeshController) GenerateTrafficPolicy(namespace, name, runtimeName string) (*types.TrafficPolicy, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.configurations[key]
	if !exists {
		return nil, fmt.Errorf("mesh configuration %s not found", key)
	}

	policy := &types.TrafficPolicy{
		Name:      runtimeName,
		Namespace: namespace,
		Rules: types.TrafficRules{
			Retry:      &config.Spec.Traffic.Retries,
			Timeout:    &config.Spec.Traffic.Timeouts,
			CircuitBreaker: &config.Spec.Traffic.CircuitBreaker,
		},
	}

	return policy, nil
}

// GetMeshStatus returns the status of mesh integration
func (c *MeshController) GetMeshStatus(namespace, name string) (*types.MeshStatus, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.configurations[key]
	if !exists {
		return nil, fmt.Errorf("mesh configuration %s not found", key)
	}

	return &types.MeshStatus{
		Enabled:         true,
		Provider:        string(config.Spec.Provider),
		MTLSMode:        string(config.Spec.MTLS.Mode),
		SidecarInjected: config.Status.SidecarCount > 0,
	}, nil
}

// GetGlobalStatus returns global mesh status
func (c *MeshController) GetGlobalStatus() map[string]interface{} {
	c.mu.RLock()
	defer c.mu.RUnlock()

	status := map[string]interface{}{
		"totalConfigurations": len(c.configurations),
		"byProvider":          make(map[string]int),
		"totalSidecars":       0,
	}

	byProvider := status["byProvider"].(map[string]int)

	for _, config := range c.configurations {
		byProvider[string(config.Spec.Provider)]++
		status["totalSidecars"] = status["totalSidecars"].(int) + config.Status.SidecarCount
	}

	return status
}

