			quota: types.ResourceQuota{
				Metadata: types.Metadata{
					Name:      "test",
					Namespace: "default",
				},
				Spec: types.ResourceQuotaSpec{
					Hard: types.ResourceLimits{
						SessionsCount: -1,
					},
				},
			},
			errors: 1,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
