package controllers

import (
	"context"
	"fmt"
	"testing"
	"time"

	"github.com/volcengine/agentcube/pkg/types"
)

func TestNewTenantController(t *testing.T) {
	c := NewTenantController()
	if c == nil {
		t.Fatal("expected non-nil controller")
	}
	if c.tenants == nil {
		t.Error("expected tenants map to be initialized")
	}
}

func TestTenantController_CreateTenant(t *testing.T) {
	c := NewTenantController()
	ctx := context.Background()

	tenant := &types.Tenant{
		Metadata: types.Metadata{
			Name: "acme-corp",
		},
		Spec: types.TenantSpec{
			DisplayName: "Acme Corporation",
			Admins:      []string{"admin@acme.com"},
			Namespaces:  []string{"acme-production"},
		},
	}

	err := c.CreateTenant(ctx, tenant)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// Test duplicate
	err = c.CreateTenant(ctx, tenant)
	if err == nil {
		t.Error("expected error for duplicate tenant")
	}
}

func TestTenantController_GetTenant(t *testing.T) {
	c := NewTenantController()
	ctx := context.Background()

	tenant := &types.Tenant{
		Metadata: types.Metadata{
			Name: "acme-corp",
		},
		Spec: types.TenantSpec{
			DisplayName: "Acme Corporation",
			Admins:      []string{"admin@acme.com"},
		},
	},
	}

	c.CreateTenant(ctx, tenant)

	got, err := c.GetTenant("acme-corp")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if got.Metadata.Name != "acme-corp" {
		t.Errorf("expected acme-corp, got %s", got.Metadata.Name)
	}

	_, err = c.GetTenant("nonexistent")
	if err == nil {
		t.Error("expected error for nonexistent tenant")
	}
}

func TestTenantController_IsNamespaceIsolated(t *testing.T) {
	c := NewTenantController()
	ctx := context.Background()

	tenant := &types.Tenant{
		Metadata: types.Metadata{
			Name: "acme-corp",
		},
		Spec: types.TenantSpec{
			DisplayName: "Acme Corporation",
			Admins:      []string{"admin@acme.com"},
			Namespaces:  []string{"acme-production", "acme-staging"},
		},
	}

	c.CreateTenant(ctx, tenant)

	if !c.IsNamespaceIsolated("acme-corp", "acme-production") {
		t.Error("expected namespace to be isolated")
	}

	if c.IsNamespaceIsolated("acme-corp", "other-namespace") {
		t.Error("expected namespace to not be isolated")
	}

	if c.IsNamespaceIsolated("nonexistent", "acme-production") {
		t.Error("expected false for nonexistent tenant")
	}
}

func TestTenantController_CreateAccessPolicy(t *testing.T) {
	c := NewTenantController()
	ctx := context.Background()

	policy := &types.TenantAccessPolicy{
		Metadata: types.Metadata{
			Name:      "cross-tenant-policy",
			Namespace: "default",
		},
		Spec: types.TenantAccessPolicySpec{
			SourceTenant: "acme-corp",
			TargetTenant: "partner-corp",
			AllowedOperations: []types.AllowedOperation{
				{
					Type: "invoke",
					Resources: []types.ResourceSelector{
						{Namespace: "partner-corp", Name: "shared-api"},
					},
				},
			},
		},
	}

	err := c.CreateAccessPolicy(ctx, policy)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
