func TestAutoscalerController_ValidateAutoscaler(t *testing.T) {
	c := NewAutoscalerController()
	ctx := context.Background()

	tests := []struct {
		name        string
		autoscaler  *types.SandboxAutoscaler
		shouldError bool
	}{
		{
			name: "valid autoscaler",
			autoscaler: &types.SandboxAutoscaler{
				Metadata: types.Metadata{
					Name:      "test",
					Namespace: "default",
				},
				Spec: types.SandboxAutoscalerSpec{
					TargetRef: types.AutoscalerTargetRef{
						Name: "my-agent",
					},
					MinReplicas: 1,
					MaxReplicas: 10,
				},
			},
			shouldError: false,
		},
		{
			name: "min > max",
			autoscaler: &types.SandboxAutoscaler{
				Metadata: types.Metadata{
					Name:      "test",
					Namespace: "default",
				},
				Spec: types.SandboxAutoscalerSpec{
					TargetRef: types.AutoscalerTargetRef{
						Name: "my-agent",
					},
					MinReplicas: 10,
					MaxReplicas: 1,
				},
