			shouldError: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := c.CreateAutoscaler(ctx, tt.autoscaler)
			if tt.shouldError && err == nil {
				t.Error("expected error")
			}
			if !tt.shouldError && err != nil {
				t.Errorf("unexpected error: %v", err)
			}
		})
	}
}

func TestAutoscalerController_EvaluateScaling(t *testing.T) {
	c := NewAutoscalerController()
	ctx := context.Background()

	autoscaler := &types.SandboxAutoscaler{
		Metadata: types.Metadata{
			Name:      "test-autoscaler",
			Namespace: "default",
		},
		Spec: types.SandboxAutoscalerSpec{
			TargetRef: types.AutoscalerTargetRef{
				Name: "my-agent",
			},
			MinReplicas: 2,
			MaxReplicas: 10,
			Metrics: []types.AutoscalingMetric{
				{
					Type: types.MetricSourceTypeResource,
					Resource: &types.ResourceMetricSource{
						Name: "cpu",
						Target: types.MetricTarget{
							Type:               types.MetricTargetTypeUtilization,
							AverageUtilization: int32Ptr(70),
						},
					},
				},
			},
		},
	}

	c.CreateAutoscaler(ctx, autoscaler)
	autoscaler.Status.CurrentReplicas = 3

	// Test scale up (high CPU)
	metrics := map[string]float64{"cpu": 85.0}
	newReplicas, shouldScale, reason := c.EvaluateScaling("default", "test-autoscaler", metrics)
	if !shouldScale {
		t.Error("expected scaling")
	}
	if newReplicas <= 3 {
		t.Errorf("expected more replicas, got %d", newReplicas)
	}
	if reason != "scale_up" {
		t.Errorf("expected scale_up, got %s", reason)
	}

	// Test scale down (low CPU)
	metrics = map[string]float64{"cpu": 30.0}
	newReplicas, shouldScale, reason = c.EvaluateScaling("default", "test-autoscaler", metrics)
	if !shouldScale {
		t.Error("expected scaling")
	}
	if newReplicas >= 3 {
		t.Errorf("expected fewer replicas, got %d", newReplicas)
	}
	if reason != "scale_down" {
		t.Errorf("expected scale_down, got %s", reason)
	}
}

