import (
	"context"
	"testing"

	"github.com/volcengine/agentcube/pkg/types"
)

func TestNewBackupController(t *testing.T) {
	c := NewBackupController()
	if c == nil {
		t.Fatal("expected non-nil controller")
	}
}

func TestBackupController_CreateBackup(t *testing.T) {
	c := NewBackupController()
	ctx := context.Background()

	backup := &types.Backup{
		Metadata: types.Metadata{
			Name:      "daily-backup",
			Namespace: "default",
		},
		Spec: types.BackupSpec{
			Resources: []types.BackupResource{
				{
					Type: "sessions",
					Selector: types.Selector{
						MatchLabels: map[string]string{
							"app": "critical",
						},
					},
				},
			},
			Storage: types.BackupStorage{
				Type: "s3",
				S3: &types.S3Storage{
					Bucket: "backups",
					Region: "us-west-2",
				},
			},
			Retention: types.RetentionPolicy{
				Count: 30,
				Age:   "720h",
			},
		},
	}

	err := c.CreateBackup(ctx, backup)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if backup.Status.Phase != types.PhasePending {
		t.Errorf("expected Pending, got %s", backup.Status.Phase)
	}
}

func TestBackupController_GetBackup(t *testing.T) {
	c := NewBackupController()
	ctx := context.Background()

	backup := &types.Backup{
		Metadata: types.Metadata{
			Name:      "test-backup",
			Namespace: "default",
		},
		Spec: types.BackupSpec{
			Resources: []types.BackupResource{{Type: "sessions"}},
			Storage:   types.BackupStorage{Type: "s3"},
		},
	}

	c.CreateBackup(ctx, backup)

	got, err := c.GetBackup("default", "test-backup")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if got.Metadata.Name != "test-backup" {
		t.Errorf("expected test-backup, got %s", got.Metadata.Name)
	}
}

func TestBackupController_CreateRestore(t *testing.T) {
	c := NewBackupController()
	ctx := context.Background()

	// First create a backup
	backup := &types.Backup{
		Metadata: types.Metadata{
			Name:      "source-backup",
			Namespace: "default",
		},
		Spec: types.BackupSpec{
			Resources: []types.BackupResource{{Type: "sessions"}},
			Storage:   types.BackupStorage{Type: "s3"},
		},
	}
	c.CreateBackup(ctx, backup)

	restore := &types.Restore{
		Metadata: types.Metadata{
			Name:      "test-restore",
			Namespace: "default",
		},
		Spec: types.RestoreSpec{
			BackupRef: types.BackupRef{
				Name:      "source-backup",
				Namespace: "default",
			},
			TargetNamespace: "restored",
			Include:         []string{"sessions"},
			ConflictPolicy:  types.ConflictPolicySkip,
		},
	}

	err := c.CreateRestore(ctx, restore)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestBackupController_ExecuteBackup(t *testing.T) {
	c := NewBackupController()
	ctx := context.Background()

	backup := &types.Backup{
		Metadata: types.Metadata{
			Name:      "test-backup",
			Namespace: "default",
		},
		Spec: types.BackupSpec{
			Resources: []types.BackupResource{
				{Type: "sessions"},
				{Type: "secrets"},
			},
			Storage: types.BackupStorage{Type: "s3"},
		},
	}

	c.CreateBackup(ctx, backup)

	result, err := c.ExecuteBackup(ctx, "default", "test-backup")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if !result.Success {
		t.Error("expected successful backup")
	}
	if result.ItemsBackedUp != 2 {
		t.Errorf("expected 2 items, got %d", result.ItemsBackedUp)
	}

	// Verify backup status
	got, _ := c.GetBackup("default", "test-backup")
	if got.Status.Phase != types.PhaseSucceeded {
		t.Errorf("expected Succeeded, got %s", got.Status.Phase)
	}
}

func TestBackupController_ListBackups(t *testing.T) {
	c := NewBackupController()
	ctx := context.Background()

	backup1 := &types.Backup{
		Metadata: types.Metadata{
			Name:      "backup-1",
			Namespace: "default",
		},
		Spec: types.BackupSpec{
			Resources: []types.BackupResource{{Type: "sessions"}},
			Storage:   types.BackupStorage{Type: "s3"},
		},
	}

	backup2 := &types.Backup{
		Metadata: types.Metadata{
			Name:      "backup-2",
			Namespace: "default",
		},
		Spec: types.BackupSpec{
			Resources: []types.BackupResource{{Type: "secrets"}},
			Storage:   types.BackupStorage{Type: "s3"},
		},
	}

	c.CreateBackup(ctx, backup1)
	c.CreateBackup(ctx, backup2)

	backups := c.ListBackups("default")
	if len(backups) != 2 {
		t.Errorf("expected 2 backups, got %d", len(backups))
	}

	backups = c.ListBackups("other")
	if len(backups) != 0 {
		t.Errorf("expected 0 backups, got %d", len(backups))
	}
}

func TestRestore_GetResourceNamespace(t *testing.T) {
	restore := &types.Restore{
		Spec: types.RestoreSpec{
			TargetNamespace: "restored",
			ResourceMapping: []types.ResourceMapping{
				{From: "production", To: "production-restored"},
			},
		},
	}

	ns := restore.GetResourceNamespace("production")
	if ns != "production-restored" {
		t.Errorf("expected production-restored, got %s", ns)
	}

	ns = restore.GetResourceNamespace("other")
	if ns != "restored" {
		t.Errorf("expected restored, got %s", ns)
	}
}

func TestRestore_ShouldInclude(t *testing.T) {
	tests := []struct {
		name     string
		include  []string
		resource string
		expected bool
	}{
		{"empty include", []string{}, "sessions", true},
		{"matching include", []string{"sessions", "secrets"}, "sessions", true},
		{"non-matching include", []string{"sessions"}, "secrets", false},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			restore := &types.Restore{
				Spec: types.RestoreSpec{
					Include: tt.include,
				},
			}
			if got := restore.ShouldInclude(tt.resource); got != tt.expected {
				t.Errorf("expected %v, got %v", tt.expected, got)
			}
		})
	}
}

