package types

import (
	"encoding/json"
)

// ComplianceFramework represents a compliance framework
type ComplianceFramework struct {
	APIVersion string                    `json:"apiVersion" yaml:"apiVersion"`
	Kind       string                    `json:"kind" yaml:"kind"`
	Metadata   Metadata                  `json:"metadata" yaml:"metadata"`
	Spec       ComplianceFrameworkSpec   `json:"spec" yaml:"spec"`
	Status     ComplianceFrameworkStatus `json:"status,omitempty" yaml:"status,omitempty"`
}

// ComplianceFrameworkSpec defines the desired state
type ComplianceFrameworkSpec struct {
	Standard     string                  `json:"standard" yaml:"standard"`
	Version      string                  `json:"version" yaml:"version"`
	Requirements []ComplianceRequirement `json:"requirements" yaml:"requirements"`
	Enforcement  EnforcementMode         `json:"enforcement" yaml:"enforcement"`
}

// ComplianceRequirement represents a compliance requirement
type ComplianceRequirement struct {
	ID       string   `json:"id" yaml:"id"`
	Name     string   `json:"name" yaml:"name"`
	Controls []string `json:"controls" yaml:"controls"`
}

// ComplianceFrameworkStatus defines the observed state
type ComplianceFrameworkStatus struct {
	Phase           Phase       `json:"phase" yaml:"phase"`
	TotalControls   int         `json:"totalControls" yaml:"totalControls"`
	PassingControls int         `json:"passingControls" yaml:"passingControls"`
	FailingControls int         `json:"failingControls" yaml:"failingControls"`
	Conditions      []Condition `json:"conditions,omitempty" yaml:"conditions,omitempty"`
}

// AuditConfig represents audit configuration
type AuditConfig struct {
	APIVersion string            `json:"apiVersion" yaml:"apiVersion"`
	Kind       string            `json:"kind" yaml:"kind"`
	Metadata   Metadata          `json:"metadata" yaml:"metadata"`
	Spec       AuditConfigSpec   `json:"spec" yaml:"spec"`
	Status     AuditConfigStatus `json:"status,omitempty" yaml:"status,omitempty"`
}

// AuditConfigSpec defines the desired state of AuditConfig
type AuditConfigSpec struct {
	Events    []string       `json:"events" yaml:"events"`
	Output    []AuditOutput  `json:"output" yaml:"output"`
	Retention AuditRetention `json:"retention" yaml:"retention"`
}

// AuditOutput represents audit output configuration
type AuditOutput struct {
	Type     string            `json:"type" yaml:"type"`
	Format   string            `json:"format" yaml:"format"`
	Path     string            `json:"path,omitempty" yaml:"path,omitempty"`
	Rotation AuditRotation     `json:"rotation,omitempty" yaml:"rotation,omitempty"`
	URL      string            `json:"url,omitempty" yaml:"url,omitempty"`
	Headers  map[string]string `json:"headers,omitempty" yaml:"headers,omitempty"`
}

// AuditRotation represents audit log rotation
type AuditRotation struct {
	MaxSize    string `json:"maxSize" yaml:"maxSize"`
	MaxAge     string `json:"maxAge" yaml:"maxAge"`
	MaxBackups int    `json:"maxBackups" yaml:"maxBackups"`
}

// AuditRetention represents audit log retention
type AuditRetention struct {
	Duration  string `json:"duration" yaml:"duration"`
	Immutable bool   `json:"immutable" yaml:"immutable"`
}

// AuditConfigStatus defines the observed state
type AuditConfigStatus struct {
	Phase      Phase       `json:"phase" yaml:"phase"`
	Events     []string    `json:"events" yaml:"events"`
	Conditions []Condition `json:"conditions,omitempty" yaml:"conditions,omitempty"`
}

// AuditEvent represents an audit event
type AuditEvent struct {
	Timestamp    string                 `json:"timestamp"`
	EventType    string                 `json:"eventType"`
	ResourceType string                 `json:"resourceType"`
	ResourceName string                 `json:"resourceName"`
	Namespace    string                 `json:"namespace"`
	User         string                 `json:"user"`
	Action       string                 `json:"action"`
	Result       string                 `json:"result"`
	Details      map[string]interface{} `json:"details"`
}

// ComplianceReport represents a compliance report
type ComplianceReport struct {
	ReportID    string              `json:"reportId"`
	GeneratedAt string              `json:"generatedAt"`
	Framework   string              `json:"framework"`
	Period      ReportPeriod        `json:"period"`
	Summary     ReportSummary       `json:"summary"`
	Findings    []ComplianceFinding `json:"findings"`
}

// ReportPeriod represents the reporting period
type ReportPeriod struct {
	Start string `json:"start"`
	End   string `json:"end"`
}

// ReportSummary represents the report summary
type ReportSummary struct {
	TotalControls int `json:"totalControls"`
	Passing       int `json:"passing"`
	Failing       int `json:"failing"`
	NotApplicable int `json:"notApplicable"`
}

// ComplianceFinding represents a compliance finding
type ComplianceFinding struct {
	ControlID      string   `json:"controlId"`
	Status         string   `json:"status"`
	Severity       string   `json:"severity"`
	Description    string   `json:"description"`
	Resources      []string `json:"resources"`
	Recommendation string   `json:"recommendation,omitempty"`
}

// ComplianceStandard represents supported compliance standards
type ComplianceStandard string

const (
	ComplianceStandardSOC2   ComplianceStandard = "SOC2"
	ComplianceStandardGDPR   ComplianceStandard = "GDPR"
	ComplianceStandardHIPAA  ComplianceStandard = "HIPAA"
	ComplianceStandardPCIDSS ComplianceStandard = "PCI-DSS"
)

// ToJSON serializes ComplianceFramework to JSON
func (c *ComplianceFramework) ToJSON() ([]byte, error) {
	return json.Marshal(c)
}

// FromJSON deserializes ComplianceFramework from JSON
func (c *ComplianceFramework) FromJSON(data []byte) error {
	return json.Unmarshal(data, c)
}

// ToJSON serializes AuditConfig to JSON
func (a *AuditConfig) ToJSON() ([]byte, error) {
	return json.Marshal(a)
}

// FromJSON deserializes AuditConfig from JSON
func (a *AuditConfig) FromJSON(data []byte) error {
	return json.Unmarshal(data, a)
}

// ToJSON serializes AuditEvent to JSON
func (e *AuditEvent) ToJSON() ([]byte, error) {
	return json.Marshal(e)
}

// FromJSON deserializes AuditEvent from JSON
func (e *AuditEvent) FromJSON(data []byte) error {
	return json.Unmarshal(data, e)
}

// Validate validates the ComplianceFramework
func (c *ComplianceFramework) Validate() []string {
	var errors []string

	if c.Metadata.Name == "" {
		errors = append(errors, "metadata.name is required")
	}

	if c.Spec.Standard == "" {
		errors = append(errors, "spec.standard is required")
	}

	if len(c.Spec.Requirements) == 0 {
		errors = append(errors, "spec.requirements cannot be empty")
	}

	return errors
}

// Validate validates the AuditConfig
func (a *AuditConfig) Validate() []string {
	var errors []string

	if a.Metadata.Name == "" {
		errors = append(errors, "metadata.name is required")
	}

	if len(a.Spec.Events) == 0 {
		errors = append(errors, "spec.events cannot be empty")
	}

	if len(a.Spec.Output) == 0 {
		errors = append(errors, "spec.output cannot be empty")
