	}

	for _, metric := range s.Spec.Metrics {
		if metric.Type == MetricSourceTypeResource && metric.Resource != nil {
			metricName := metric.Resource.Name
			if value, ok := metrics[metricName]; ok {
				if metric.Resource.Target.Type == MetricTargetTypeUtilization {
					targetUtilization := float64(*metric.Resource.Target.AverageUtilization)
					if value > targetUtilization && currentReplicas < s.Spec.MaxReplicas {
