package controllers

import (
	"context"
	"fmt"
	"sync"
	"time"

	"github.com/agentcube/agentcube/pkg/types"
)

// ComplianceController manages compliance and governance
type ComplianceController struct {
	frameworks   map[string]*types.ComplianceFramework
	auditConfigs map[string]*types.AuditConfig
	auditLogs    []types.AuditEvent
	reports      map[string]*types.ComplianceReport
	mu           sync.RWMutex
	maxLogSize   int
}

// NewComplianceController creates a new compliance controller
func NewComplianceController() *ComplianceController {
	return &ComplianceController{
		frameworks:   make(map[string]*types.ComplianceFramework),
		auditConfigs: make(map[string]*types.AuditConfig),
		auditLogs:    make([]types.AuditEvent, 0),
		reports:      make(map[string]*types.ComplianceReport),
		maxLogSize:   100000,
	}
}

// CreateFramework creates a new compliance framework
func (c *ComplianceController) CreateFramework(ctx context.Context, framework *types.ComplianceFramework) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	if _, exists := c.frameworks[framework.Metadata.Name]; exists {
		return fmt.Errorf("compliance framework %s already exists", framework.Metadata.Name)
	}

	errors := framework.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	framework.Status.Phase = types.PhasePending
	framework.Status.TotalControls = len(framework.GetAllControls())
	c.frameworks[framework.Metadata.Name] = framework

	return nil
}

// GetFramework gets a compliance framework
func (c *ComplianceController) GetFramework(name string) (*types.ComplianceFramework, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	framework, exists := c.frameworks[name]
	if !exists {
		return nil, fmt.Errorf("compliance framework %s not found", name)
	}

	return framework, nil
}

// UpdateFramework updates a compliance framework
func (c *ComplianceController) UpdateFramework(ctx context.Context, framework *types.ComplianceFramework) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	if _, exists := c.frameworks[framework.Metadata.Name]; !exists {
		return fmt.Errorf("compliance framework %s not found", framework.Metadata.Name)
	}

	errors := framework.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	framework.Status.TotalControls = len(framework.GetAllControls())
	c.frameworks[framework.Metadata.Name] = framework
	return nil
}

// DeleteFramework deletes a compliance framework
func (c *ComplianceController) DeleteFramework(name string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	if _, exists := c.frameworks[name]; !exists {
		return fmt.Errorf("compliance framework %s not found", name)
	}

	delete(c.frameworks, name)
	return nil
}

// ListFrameworks lists all compliance frameworks
func (c *ComplianceController) ListFrameworks() []*types.ComplianceFramework {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.ComplianceFramework
	for _, framework := range c.frameworks {
		result = append(result, framework)
	}

	return result
}

// CreateAuditConfig creates an audit configuration
func (c *ComplianceController) CreateAuditConfig(ctx context.Context, config *types.AuditConfig) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	key := fmt.Sprintf("%s/%s", config.Metadata.Namespace, config.Metadata.Name)

	if _, exists := c.auditConfigs[key]; exists {
		return fmt.Errorf("audit config %s already exists", key)
	}

	errors := config.Validate()
	if len(errors) > 0 {
		return fmt.Errorf("validation failed: %v", errors)
	}

	config.Status.Phase = types.PhasePending
	config.Status.Events = config.Spec.Events
	c.auditConfigs[key] = config

	return nil
}

// GetAuditConfig gets an audit configuration
func (c *ComplianceController) GetAuditConfig(namespace, name string) (*types.AuditConfig, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.auditConfigs[key]
	if !exists {
		return nil, fmt.Errorf("audit config %s not found", key)
	}

	return config, nil
}

// LogAuditEvent logs an audit event
func (c *ComplianceController) LogAuditEvent(event types.AuditEvent) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	// Check if any audit config is interested in this event
	shouldLog := false
	for _, config := range c.auditConfigs {
		if config.Spec.Namespace == "" || config.Spec.Namespace == event.Namespace {
			if config.IsEventAudited(event.EventType) {
				shouldLog = true
				break
			}
		}
	}

	if !shouldLog {
		return nil
	}

	c.auditLogs = append(c.auditLogs, event)

	// Trim logs if needed
	if len(c.auditLogs) > c.maxLogSize {
		c.auditLogs = c.auditLogs[len(c.auditLogs)-c.maxLogSize:]
	}

	return nil
}

// GetAuditLogs gets audit logs with optional filtering
func (c *ComplianceController) GetAuditLogs(namespace, resourceType, eventType string, limit int) []types.AuditEvent {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []types.AuditEvent
	for i := len(c.auditLogs) - 1; i >= 0 && len(result) < limit; i-- {
		event := c.auditLogs[i]

		if namespace != "" && event.Namespace != namespace {
			continue
		}
		if resourceType != "" && event.ResourceType != resourceType {
			continue
		}
		if eventType != "" && event.EventType != eventType {
			continue
		}

		result = append(result, event)
	}

	return result
}

// GenerateReport generates a compliance report
func (c *ComplianceController) GenerateReport(ctx context.Context, frameworkName string, startTime, endTime string) (*types.ComplianceReport, error) {
	c.mu.Lock()
	defer c.mu.Unlock()

	framework, exists := c.frameworks[frameworkName]
	if !exists {
		return nil, fmt.Errorf("compliance framework %s not found", frameworkName)
	}

	report := &types.ComplianceReport{
		ReportID:    fmt.Sprintf("rpt-%d", time.Now().Unix()),
		GeneratedAt: time.Now().Format(time.RFC3339),
		Framework:   framework.Spec.Standard,
		Period: types.ReportPeriod{
			Start: startTime,
			End:   endTime,
		},
		Summary: types.ReportSummary{
			TotalControls: len(framework.GetAllControls()),
			Passing:       framework.Status.PassingControls,
			Failing:       framework.Status.FailingControls,
			NotApplicable: 0,
		},
		Findings: []types.ComplianceFinding{},
	}

	c.reports[report.ReportID] = report

	return report, nil
}

// GetReport gets a compliance report
func (c *ComplianceController) GetReport(reportID string) (*types.ComplianceReport, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	report, exists := c.reports[reportID]
	if !exists {
		return nil, fmt.Errorf("compliance report %s not found", reportID)
	}

	return report, nil
}

// ListReports lists all compliance reports
func (c *ComplianceController) ListReports() []*types.ComplianceReport {
	c.mu.RLock()
	defer c.mu.RUnlock()

	var result []*types.ComplianceReport
	for _, report := range c.reports {
		result = append(result, report)
	}

	return result
}

// EvaluateCompliance evaluates compliance for a framework
func (c *ComplianceController) EvaluateCompliance(ctx context.Context, frameworkName string) error {
	c.mu.Lock()
	defer c.mu.Unlock()

	framework, exists := c.frameworks[frameworkName]
	if !exists {
		return fmt.Errorf("compliance framework %s not found", frameworkName)
	}

	// In real implementation, would actually evaluate compliance
	// For now, just update status
	framework.Status.Phase = types.PhaseRunning

	// Simulate evaluation
	framework.Status.PassingControls = framework.Status.TotalControls - 2
	framework.Status.FailingControls = 2
	framework.Status.Phase = types.PhaseSucceeded

	return nil
}

// CheckControl checks a specific control
func (c *ComplianceController) CheckControl(frameworkName, controlID string) (bool, string, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	framework, exists := c.frameworks[frameworkName]
	if !exists {
		return false, "", fmt.Errorf("compliance framework %s not found", frameworkName)
	}

	req := framework.GetRequirementByID(controlID)
	if req == nil {
		return false, "", fmt.Errorf("requirement %s not found in framework %s", controlID, frameworkName)
	}

	// In real implementation, would actually check the control
	// For now, simulate pass/fail
	return true, fmt.Sprintf("Control %s (%s) is compliant", controlID, req.Name), nil
}

// GetAuditRetention gets audit retention configuration
func (c *ComplianceController) GetAuditRetention(namespace, name string) (*types.AuditRetention, error) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	key := fmt.Sprintf("%s/%s", namespace, name)
	config, exists := c.auditConfigs[key]
	if !exists {
		return nil, fmt.Errorf("audit config %s not found", key)
	}

	return &config.Spec.Retention, nil
}

// CleanupOldAuditLogs removes old audit logs based on retention policy
func (c *ComplianceController) CleanupOldAuditLogs() error {
	c.mu.Lock()
	defer c.mu.Unlock()

	now := time.Now()

	for _, config := range c.auditConfigs {
		retention, _ := time.ParseDuration(config.Spec.Retention.Duration)
		if retention > 0 {
			newLogs := make([]types.AuditEvent, 0)
			for _, log := range c.auditLogs {
				logTime, _ := time.Parse(time.RFC3339, log.Timestamp)
				if now.Sub(logTime) <= retention {
					newLogs = append(newLogs, log)
				}
			}
			c.auditLogs = newLogs
		}
	}

	return nil
}

// ExportAuditLogs exports audit logs
func (c *ComplianceController) ExportAuditLogs(namespace string, startTime, endTime string) ([]types.AuditEvent, error) {
	c.mu.RLock()
