	c.UpdateCheckpoint(ctx, checkpoint)

	// Delete
	err := c.DeleteCheckpoint("default", "test-checkpoint", storage)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	_, err = c.GetCheckpoint("default", "test-checkpoint")
	if err == nil {
		t.Error("expected error after deletion")
	}
}

func TestCheckpointController_RecoverSession(t *testing.T) {
	c := NewCheckpointController()
	backend := NewInMemoryStorageBackend()
	c.RegisterStorageBackend("memory", backend)

	ctx := context.Background()

	// Create checkpoint
	checkpoint := &types.Checkpoint{
		Metadata: types.Metadata{
			Name:      "checkpoint-1",
			Namespace: "default",
		},
		Spec: types.CheckpointSpec{
			SessionID: "session-123",
		},
	}
	c.CreateCheckpoint(ctx, checkpoint)

	// Save state
	state := &types.SessionState{
		SessionID:    "session-123",
		CheckpointID: "checkpoint-1",
	}
	storage := types.CheckpointStorage{Type: "memory"}
	c.SaveSessionState(ctx, "session-123", state, storage)

	// Recover
	req := &types.RecoveryRequest{
		SessionID: "session-123",
		Scenario:  types.RecoveryPodFailure,
	}

	result, err := c.RecoverSession(ctx, req, storage)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if !result.Success {
		t.Errorf("expected successful recovery, got: %s", result.ErrorMessage)
	}
	if result.NewPodName == "" {
		t.Error("expected NewPodName to be set")
	}
}

func TestCheckpointController_CleanupOldCheckpoints(t *testing.T) {
	c := NewCheckpointController()
	backend := NewInMemoryStorageBackend()
	c.RegisterStorageBackend("memory", backend)

	ctx := context.Background()
	storage := types.CheckpointStorage{Type: "memory"}

	// Create multiple checkpoints
	for i := 0; i < 5; i++ {
		checkpoint := &types.Checkpoint{
			Metadata: types.Metadata{
				Name:      fmt.Sprintf("checkpoint-%d", i),
				Namespace: "default",
			},
			Spec: types.CheckpointSpec{
				SessionID: "session-123",
			},
		}
		c.CreateCheckpoint(ctx, checkpoint)

		state := &types.SessionState{
			SessionID:    "session-123",
			CheckpointID: fmt.Sprintf("checkpoint-%d", i),
		}
		c.SaveSessionState(ctx, "session-123", state, storage)
	}

	policy := types.CheckpointRetentionPolicy{
		MaxCheckpoints: 3,
	}

	err := c.CleanupOldCheckpoints("session-123", policy, storage)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	checkpoints := c.ListCheckpoints("session-123")
	if len(checkpoints) != 3 {
		t.Errorf("expected 3 checkpoints after cleanup, got %d", len(checkpoints))
	}
}

func TestInMemoryStorageBackend(t *testing.T) {
	backend := NewInMemoryStorageBackend()

	// Test Save
	data := []byte("test data")
	err := backend.Save("test/key", data)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// Test Load
	loaded, err := backend.Load("test/key")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if string(loaded) != string(data) {
		t.Errorf("expected %s, got %s", string(data), string(loaded))
	}

	// Test Load not found
	_, err = backend.Load("nonexistent")
	if err == nil {
		t.Error("expected error for nonexistent key")
	}

	// Test Delete
	err = backend.Delete("test/key")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// Test List
	backend.Save("prefix/key1", []byte("data1"))
	backend.Save("prefix/key2", []byte("data2"))
	backend.Save("other/key3", []byte("data3"))

	keys, err := backend.List("prefix/")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(keys) != 2 {
		t.Errorf("expected 2 keys, got %d", len(keys))
	}
}

